import com.alibaba.fastjson.JSONObject;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import java.util.Map;
import java.util.HashMap;

Logger logger = LoggerFactory.getLogger("fulltest_credit_xml_request_pre_v2");

@Override
public void afterInitHttpContext(ChannelContext context, HttpContext httpContext) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    EtlRequestResult etlRequestResult = etlHandlerContext.getEtlRequestResult();
    Map<String, String> allParam = etlRequestResult.getAllParam();
    Map<String, String> requestInParam = etlHandlerContext.getRequestInParam();
    if (requestInParam == null) { requestInParam = new HashMap<String, String>(); }

    String[] fixedParams = {"transCode", "sysId", "userId", "password",
                            "entCertType", "queryReason", "queryType",
                            "reportType", "reportModelType"};
    for (String param : fixedParams) {
        String val = (String) requestInParam.get(param);
        if (val == null || val.trim().isEmpty()) {
            val = allParam != null ? (String) allParam.get(param) : null;
