import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import java.util.Map;
import java.util.HashMap;
import java.util.List;
import java.util.ArrayList;

Logger logger = LoggerFactory.getLogger("fulltest_qcc_740_page_post_v2");

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    Map<String, Object> outputMap = new HashMap<String, Object>();

    if (response == null || response.trim().isEmpty()) {
        logger.error("QCC 740 post: response is null or empty");
        outputMap.put("dishonestcnt", 0);
        outputMap.put("dishonestcntdetail", "[]");
        outputMap.put("statusCode740sxhc", "500");
        return outputMap;
    }

    try {
        JSONObject respJson = JSONObject.parseObject(response);
        String status = respJson.getString("Status");

        if (!"200".equals(status)) {
            logger.warn("QCC 740 post: Status={}, not 200", status);
            outputMap.put("dishonestcnt", 0);
            outputMap.put("dishonestcntdetail", "[]");
            outputMap.put("statusCode740sxhc", status != null ? status : "500");
            return outputMap;
        }

        JSONObject result = respJson.getJSONObject("Result");
        if (result == null) {
            outputMap.put("dishonestcnt", 0);
            outputMap.put("dishonestcntdetail", "[]");
            outputMap.put("statusCode740sxhc", status);
            return outputMap;
        }

        JSONObject dataObj = result.getJSONObject("Data");
        JSONArray dataArray = null;
        if (dataObj != null) {
            dataArray = dataObj.getJSONArray("Data");
        }
        if (dataArray == null) {
            dataArray = result.getJSONArray("Data");
        }

        if (dataArray == null || dataArray.size() == 0) {
            outputMap.put("dishonestcnt", 0);
            outputMap.put("dishonestcntdetail", "[]");
            outputMap.put("statusCode740sxhc", status);
            return outputMap;
        }

        long nowMs = System.currentTimeMillis();
        long ninetyDaysMs = 90L * 24 * 60 * 60 * 1000;
        long cutoffMs = nowMs - ninetyDaysMs;

        List<JSONObject> filteredRecords = new ArrayList<JSONObject>();

        for (int i = 0; i < dataArray.size(); i++) {
            JSONObject record = dataArray.getJSONObject(i);
            String liandate = record.getString("Liandate");
            String publicdate = record.getString("Publicdate");

            boolean withinRange = false;
            if (liandate != null && !liandate.isEmpty()) {
                try {
                    long lianMs = Long.parseLong(liandate);
                    if (lianMs >= cutoffMs) { withinRange = true; }
                } catch (NumberFormatException e) {
                    logger.debug("QCC 740 post: Liandate parse failed for record {}", i);
                }
            }
            if (!withinRange && publicdate != null && !publicdate.isEmpty()) {
                try {
                    long pubMs = Long.parseLong(publicdate);
                    if (pubMs >= cutoffMs) { withinRange = true; }
                } catch (NumberFormatException e) {
                    logger.debug("QCC 740 post: Publicdate parse failed for record {}", i);
                }
            }

            if (withinRange) {
                JSONObject detail = new JSONObject();
                detail.put("caseNo", record.getString("Anno"));
                detail.put("court", record.getString("Executegov"));
                detail.put("amount", record.getString("Amount"));
                detail.put("publishDate", record.getString("Publicdate"));
                filteredRecords.add(detail);
            }
        }

        outputMap.put("dishonestcnt", filteredRecords.size());
        outputMap.put("dishonestcntdetail", JSON.toJSONString(filteredRecords));
        outputMap.put("statusCode740sxhc", status);

        logger.info("QCC 740 post: totalRecords={}, filteredRecent3m={}",
                     dataArray.size(), filteredRecords.size());

    } catch (Exception e) {
        logger.error("QCC 740 post: exception parsing response", e);
        outputMap.put("dishonestcnt", 0);
        outputMap.put("dishonestcntdetail", "[]");
        outputMap.put("statusCode740sxhc", "500");
    }

    return outputMap;
}

