private String fullWidthToHalfWidth(String s) {
    if (s == null) return null;
    StringBuilder sb = new StringBuilder(s.length());
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == 12288) {
            sb.append(' ');
        } else if (c >= 65281 && c <= 65374) {
            sb.append((char)(c - 65248));
        } else {
            sb.append(c);
        }
    }
    return sb.toString();
}

