import java.util.HashMap;

Logger logger = LoggerFactory.getLogger("fulltest_socket_xml_post");

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    Map<String, Object> outputMap = new HashMap<String, Object>();

    if (response == null || response.trim().isEmpty()) {
        logger.error("Socket XML post: response is null or empty");
        outputMap.put("riskLevel", "");
        outputMap.put("code", "500");
        return outputMap;
    }

    try {
        String code = extractTagValue(response, "code");
        String riskLevel = extractTagValue(response, "riskLevel");

        if (code == null) { code = "500"; }
        if (riskLevel == null) { riskLevel = ""; }

        if (!"200".equals(code)) {
            logger.warn("Socket XML post: code={}, setting riskLevel to empty", code);
            riskLevel = "";
        }

        outputMap.put("riskLevel", riskLevel);
        outputMap.put("code", code);

        logger.info("Socket XML post: code={}, riskLevel={}", code, riskLevel);

    } catch (Exception e) {
        logger.error("Socket XML post: exception parsing response", e);
        outputMap.put("riskLevel", "");
        outputMap.put("code", "500");
    }

    return outputMap;
}

private String extractTagValue(String xml, String tagName) {
    int start = xml.indexOf("<" + tagName + ">");
    if (start < 0) {
        start = xml.indexOf("<" + tagName + " ");
        if (start < 0) return null;
        int gtPos = xml.indexOf(">", start);
        if (gtPos < 0) return null;
        int end = xml.indexOf("</" + tagName + ">", gtPos);
        if (end < 0) return null;
        return xml.substring(gtPos + 1, end).trim();
    }
    int end = xml.indexOf("</" + tagName + ">", start);
    if (end < 0) return null;
    return xml.substring(start + tagName.length() + 2, end).trim();
}

