Logger logger = LoggerFactory.getLogger("fulltest_yjt_news_post");

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    Map<String, Object> outputMap = new HashMap<String, Object>();

    if (response == null || response.trim().isEmpty()) {
        logger.error("YJT news post: response is null or empty");
        outputMap.put("negnewscnt", 0);
        outputMap.put("enterprisenegativesentiment3m", "[]");
        outputMap.put("yjtxwyqstatuscode", "201");
        return outputMap;
    }

    try {
        JSONArray rows = JSONArray.parseArray(response);
        if (rows == null || rows.size() == 0) {
            logger.info("YJT news post: no news data found");
            outputMap.put("negnewscnt", 0);
            outputMap.put("enterprisenegativesentiment3m", "[]");
            outputMap.put("yjtxwyqstatuscode", "201");
            return outputMap;
        }

        int negNewsCnt = 0;
        List<JSONObject> negativeSentiments = new ArrayList<JSONObject>();

        for (int i = 0; i < rows.size(); i++) {
            JSONObject row = rows.getJSONObject(i);

            boolean isNegative = false;

            String sentimentScoreStr = row.getString("SENTIMENT_SCORE");
            if (sentimentScoreStr != null && !sentimentScoreStr.isEmpty()) {
                try {
                    double score = Double.parseDouble(sentimentScoreStr);
                    if (score < 0) { isNegative = true; }
                } catch (NumberFormatException e) {
                    logger.debug("YJT news post: SENTIMENT_SCORE parse failed for row {}", i);
                }
            }

            String riskLevel = row.getString("RISK_LEVEL");
            if (riskLevel != null && ("HIGH".equalsIgnoreCase(riskLevel) || "MEDIUM".equalsIgnoreCase(riskLevel))) {
                isNegative = true;
            }

            if (isNegative) {
                negNewsCnt++;
                JSONObject detail = new JSONObject();
                detail.put("title", row.getString("TITLE"));
                detail.put("source", row.getString("SOURCE"));
                detail.put("date", row.getString("PUBLISH_DATE"));
                detail.put("score", sentimentScoreStr);
                negativeSentiments.add(detail);
            }
        }

        outputMap.put("negnewscnt", negNewsCnt);
        outputMap.put("enterprisenegativesentiment3m", JSON.toJSONString(negativeSentiments));
        outputMap.put("yjtxwyqstatuscode", negNewsCnt > 0 ? "200" : "201");

        logger.info("YJT news post: totalRows={}, negNewsCnt={}", rows.size(), negNewsCnt);

    } catch (Exception e) {
        logger.error("YJT news post: exception parsing response", e);
        outputMap.put("negnewscnt", 0);
        outputMap.put("enterprisenegativesentiment3m", "[]");
        outputMap.put("yjtxwyqstatuscode", "500");
    }

    return outputMap;
}

