Logger logger = LoggerFactory.getLogger("fulltest_yjt_regfin_quar_post");

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    Map<String, Object> outputMap = new HashMap<String, Object>();

    if (response == null || response.trim().isEmpty()) {
        logger.error("YJT regfin quar post: response is null or empty");
        outputMap.put("fiscalselfsufficiencyrate", 0.0);
        outputMap.put("fiscalselfsufficiencycurrentmonth", 0.0);
        outputMap.put("fiscalselfsufficiencylastmonth", 0.0);
        outputMap.put("yjtqyjjyddqstatuscode", "500");
        return outputMap;
    }

    try {
        JSONArray rows = JSONArray.parseArray(response);
        if (rows == null || rows.size() == 0) {
            logger.warn("YJT regfin quar post: empty result set");
            outputMap.put("fiscalselfsufficiencyrate", 0.0);
            outputMap.put("fiscalselfsufficiencycurrentmonth", 0.0);
            outputMap.put("fiscalselfsufficiencylastmonth", 0.0);
            outputMap.put("yjtqyjjyddqstatuscode", "201");
            return outputMap;
        }

        Calendar cal = Calendar.getInstance();
        int currentMonth = cal.get(Calendar.MONTH) + 1;
        int currentYear = cal.get(Calendar.YEAR);
        String currentQuar;
        if (currentMonth <= 3) { currentQuar = currentYear + "Q1"; }
        else if (currentMonth <= 6) { currentQuar = currentYear + "Q2"; }
        else if (currentMonth <= 9) { currentQuar = currentYear + "Q3"; }
        else { currentQuar = currentYear + "Q4"; }

        int prevMonth = currentMonth - 3;
        int prevYear = currentYear;
        if (prevMonth <= 0) { prevMonth += 12; prevYear--; }
        String prevQuar;
        if (prevMonth <= 3) { prevQuar = prevYear + "Q1"; }
        else if (prevMonth <= 6) { prevQuar = prevYear + "Q2"; }
        else if (prevMonth <= 9) { prevQuar = prevYear + "Q3"; }
        else { prevQuar = prevYear + "Q4"; }

        double currentRevenue = 0.0;
        double currentExpenditure = 0.0;
        double prevRevenue = 0.0;
        double prevExpenditure = 0.0;

        for (int i = 0; i < rows.size(); i++) {
            JSONObject row = rows.getJSONObject(i);
            String quar = row.getString("QUAR");
            String indName = row.getString("INDICNAME");
            String mvalueStr = row.getString("MVALUE");

            if (quar == null || indName == null || mvalueStr == null) continue;

            double mvalue = 0.0;
            try { mvalue = Double.parseDouble(mvalueStr); }
            catch (NumberFormatException e) { continue; }

            if (quar.equals(currentQuar)) {
                if (indName.contains("收入") || indName.toUpperCase().contains("REVENUE")) {
                    currentRevenue = mvalue;
                } else if (indName.contains("支出") || indName.toUpperCase().contains("EXPENDITURE")) {
                    currentExpenditure = mvalue;
                }
            } else if (quar.equals(prevQuar)) {
                if (indName.contains("收入") || indName.toUpperCase().contains("REVENUE")) {
                    prevRevenue = mvalue;
                } else if (indName.contains("支出") || indName.toUpperCase().contains("EXPENDITURE")) {
                    prevExpenditure = mvalue;
                }
            }
        }

        double currentRate = 0.0;
        double prevRate = 0.0;
        String statusCode = "200";

        if (currentExpenditure > 0) {
            currentRate = (currentRevenue / currentExpenditure) * 100.0;
        } else {
            statusCode = "206";
            logger.warn("YJT regfin quar post: current quarter expenditure is zero or missing");
        }

        if (prevExpenditure > 0) {
            prevRate = (prevRevenue / prevExpenditure) * 100.0;
        }

        outputMap.put("fiscalselfsufficiencyrate", Math.round(currentRate * 100.0) / 100.0);
        outputMap.put("fiscalselfsufficiencycurrentmonth", Math.round(currentRate * 100.0) / 100.0);
        outputMap.put("fiscalselfsufficiencylastmonth", Math.round(prevRate * 100.0) / 100.0);
        outputMap.put("yjtqyjjyddqstatuscode", statusCode);

        logger.info("YJT regfin quar post: curQ={}, curRate={}, prevQ={}, prevRate={}, status={}",
                     currentQuar, currentRate, prevQuar, prevRate, statusCode);

    } catch (Exception e) {
        logger.error("YJT regfin quar post: exception parsing response", e);
        outputMap.put("fiscalselfsufficiencyrate", 0.0);
        outputMap.put("fiscalselfsufficiencycurrentmonth", 0.0);
        outputMap.put("fiscalselfsufficiencylastmonth", 0.0);
        outputMap.put("yjtqyjjyddqstatuscode", "500");
    }

    return outputMap;
}

