Logger logger = LoggerFactory.getLogger("fulltest_credit_ws_post");

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    Map<String, Object> outputMap = new HashMap<String, Object>();
    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
    if (bussMap == null) { bussMap = new HashMap<String, Object>(); }

    if (response == null || response.trim().isEmpty()) {
        logger.error("Credit WS post: response is null or empty");
        outputMap.put("qyzxbgreportid", "");
        outputMap.put("qyzxbgstatuscode", "500");
        outputMap.put("odacctavg", 0.0);
        return outputMap;
    }

    try {
        String reportId = extractSoapTagValue(response, "reportId");
        if (reportId == null) {
            reportId = extractSoapTagValue(response, "ReportId");
        }
        if (reportId == null) { reportId = ""; }

        String statusCode = extractSoapTagValue(response, "processingStatus");
        if (statusCode == null) {
            statusCode = extractSoapTagValue(response, "statusCode");
        }
        if (statusCode == null) { statusCode = "200"; }

        int odLoanAcctCnt = 0;
        int odGuaAcctCnt = 0;

        Object loanCntObj = bussMap.get("odloanacctcnt");
        if (loanCntObj != null) {
            try { odLoanAcctCnt = Integer.parseInt(loanCntObj.toString()); }
            catch (NumberFormatException e) { odLoanAcctCnt = 0; }
        } else {
            String loanCntStr = extractSoapTagValue(response, "odloanacctcnt");
            if (loanCntStr != null && !loanCntStr.isEmpty()) {
                try { odLoanAcctCnt = Integer.parseInt(loanCntStr); }
                catch (NumberFormatException e) { odLoanAcctCnt = 0; }
            } else {
                logger.warn("Credit WS post: odloanacctcnt node missing, treated as 0");
            }
        }

        Object guaCntObj = bussMap.get("odguaacctcnt");
        if (guaCntObj != null) {
            try { odGuaAcctCnt = Integer.parseInt(guaCntObj.toString()); }
            catch (NumberFormatException e) { odGuaAcctCnt = 0; }
        } else {
            String guaCntStr = extractSoapTagValue(response, "odguaacctcnt");
            if (guaCntStr != null && !guaCntStr.isEmpty()) {
                try { odGuaAcctCnt = Integer.parseInt(guaCntStr); }
                catch (NumberFormatException e) { odGuaAcctCnt = 0; }
            } else {
                logger.warn("Credit WS post: odguaacctcnt node missing, treated as 0");
            }
        }

        double odAcctAvg = (odLoanAcctCnt + odGuaAcctCnt) / 2.0;

        outputMap.put("qyzxbgreportid", reportId);
        outputMap.put("qyzxbgstatuscode", statusCode);
        outputMap.put("odacctavg", odAcctAvg);

        logger.info("Credit WS post: reportId={}, status={}, odLoan={}, odGua={}, avg={}",
                     reportId, statusCode, odLoanAcctCnt, odGuaAcctCnt, odAcctAvg);

    } catch (Exception e) {
        logger.error("Credit WS post: exception parsing SOAP response", e);
        outputMap.put("qyzxbgreportid", "");
        outputMap.put("qyzxbgstatuscode", "500");
        outputMap.put("odacctavg", 0.0);
    }

    return outputMap;
}

private String extractSoapTagValue(String xml, String tagName) {
    int start = xml.indexOf("<" + tagName + ">");
    if (start < 0) {
        start = xml.indexOf("<" + tagName + " ");
        if (start < 0) return null;
        int gtPos = xml.indexOf(">", start);
        if (gtPos < 0) return null;
        int end = xml.indexOf("</" + tagName + ">", gtPos);
        if (end < 0) return null;
        return xml.substring(gtPos + 1, end).trim();
    }
    int end = xml.indexOf("</" + tagName + ">", start);
    if (end < 0) return null;
    return xml.substring(start + tagName.length() + 2, end).trim();
}

