@Override
public Map<String, Object> after(ChannelContext context, String response) {
    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
    Map<String, Object> outputMap = new HashMap<String, Object>();

    if (response == null || response.trim().isEmpty()) {
        logger.error("Credit XML post: response is null or empty");
        outputMap.put("odloanacctcnt", 0);
        outputMap.put("odloanacctcntdetail", "[]");
        outputMap.put("odguaacctcnt", 0);
        outputMap.put("odguaacctcntdetail", "[]");
        outputMap.put("qyzxbgstatuscode", "500");
        outputMap.put("qyzxbgreportid", "");
        return outputMap;
    }

    try {
        String reportId = "";
        String statusCode = "";
        int odLoanAcctCnt = 0;
        int odGuaAcctCnt = 0;
        List<JSONObject> odLoanDetails = new ArrayList<JSONObject>();
        List<JSONObject> odGuaDetails = new ArrayList<JSONObject>();

        int riStart = response.indexOf("<reportId>");
        int riEnd = response.indexOf("</reportId>");
        if (riStart >= 0 && riEnd > riStart) {
            reportId = response.substring(riStart + 10, riEnd).trim();
        }

        int psStart = response.indexOf("<processingStatus>");
        int psEnd = response.indexOf("</processingStatus>");
        if (psStart >= 0 && psEnd > psStart) {
            statusCode = response.substring(psStart + 18, psEnd).trim();
        }
        if (statusCode.isEmpty()) {
            int scStart = response.indexOf("<statusCode>");
            int scEnd = response.indexOf("</statusCode>");
            if (scStart >= 0 && scEnd > scStart) {
                statusCode = response.substring(scStart + 12, scEnd).trim();
            }
        }

        String loanSection = extractSection(response, "loanAccountInformation");
        if (loanSection != null && !loanSection.isEmpty()) {
            int searchFrom = 0;
            while (true) {
                int accStart = loanSection.indexOf("<accountRecord>", searchFrom);
                if (accStart < 0) break;
                int accEnd = loanSection.indexOf("</accountRecord>", accStart);
                if (accEnd < 0) break;
                String accXml = loanSection.substring(accStart, accEnd + 16);
                searchFrom = accEnd + 16;

                boolean unsettled = false;
                String fiveLevel = extractTagValue(accXml, "FiveLevelCategory");
                String closed = extractTagValue(accXml, "Closed");
                if (fiveLevel != null && !fiveLevel.isEmpty() && !"N/A".equals(fiveLevel)) {
                    unsettled = true;
                }
                if ("0".equals(closed)) {
                    unsettled = true;
                }

                if (unsettled) {
                    String totalOverdue = extractTagValue(accXml, "totaloverdue");
                    String overduePrincipal = extractTagValue(accXml, "overdueprincipal");
                    boolean hasOverdue = false;
                    if (totalOverdue != null && !totalOverdue.isEmpty()) {
                        try {
                            if (Double.parseDouble(totalOverdue) > 0) hasOverdue = true;
                        } catch (NumberFormatException e) { /* ignore */ }
                    }
                    if (overduePrincipal != null && !overduePrincipal.isEmpty()) {
                        try {
                            if (Double.parseDouble(overduePrincipal) > 0) hasOverdue = true;
                        } catch (NumberFormatException e) { /* ignore */ }
                    }
                    if (hasOverdue) {
                        odLoanAcctCnt++;
                        JSONObject detail = new JSONObject();
                        detail.put("accountNo", extractTagValue(accXml, "accountNumber"));
                        detail.put("fiveLevelCategory", fiveLevel);
                        detail.put("totalOverdue", totalOverdue);
                        detail.put("overduePrincipal", overduePrincipal);
                        odLoanDetails.add(detail);
                    }
                }
            }
        }

        String guaSection = extractSection(response, "guaranteeAccountInformation");
        if (guaSection != null && !guaSection.isEmpty()) {
            int searchFrom = 0;
            while (true) {
                int accStart = guaSection.indexOf("<guaranteeRecord>", searchFrom);
                if (accStart < 0) break;
                int accEnd = guaSection.indexOf("</guaranteeRecord>", accStart);
                if (accEnd < 0) break;
                String accXml = guaSection.substring(accStart, accEnd + 18);
                searchFrom = accEnd + 18;

                boolean unsettled = false;
                String fiveLevel = extractTagValue(accXml, "FiveLevelCategory");
                String closed = extractTagValue(accXml, "Closed");
                if (fiveLevel != null && !fiveLevel.isEmpty() && !"N/A".equals(fiveLevel)) {
                    unsettled = true;
                }
                if ("0".equals(closed)) {
                    unsettled = true;
                }

                if (unsettled) {
                    String totalOverdue = extractTagValue(accXml, "totaloverdue");
                    String overduePrincipal = extractTagValue(accXml, "overdueprincipal");
                    boolean hasOverdue = false;
                    if (totalOverdue != null && !totalOverdue.isEmpty()) {
                        try {
                            if (Double.parseDouble(totalOverdue) > 0) hasOverdue = true;
                        } catch (NumberFormatException e) { /* ignore */ }
                    }
                    if (overduePrincipal != null && !overduePrincipal.isEmpty()) {
                        try {
                            if (Double.parseDouble(overduePrincipal) > 0) hasOverdue = true;
                        } catch (NumberFormatException e) { /* ignore */ }
                    }
                    if (hasOverdue) {
                        odGuaAcctCnt++;
                        JSONObject detail = new JSONObject();
                        detail.put("guaranteeNo", extractTagValue(accXml, "guaranteeNumber"));
                        detail.put("fiveLevelCategory", fiveLevel);
                        detail.put("totalOverdue", totalOverdue);
                        detail.put("overduePrincipal", overduePrincipal);
                        odGuaDetails.add(detail);
                    }
                }
            }
        }

        outputMap.put("odloanacctcnt", odLoanAcctCnt);
        outputMap.put("odloanacctcntdetail", JSON.toJSONString(odLoanDetails));
        outputMap.put("odguaacctcnt", odGuaAcctCnt);
        outputMap.put("odguaacctcntdetail", JSON.toJSONString(odGuaDetails));
        outputMap.put("qyzxbgstatuscode", statusCode.isEmpty() ? "200" : statusCode);
        outputMap.put("qyzxbgreportid", reportId);

        logger.info("Credit XML post: reportId={}, status={}, odLoan={}, odGua={}",
                     reportId, statusCode, odLoanAcctCnt, odGuaAcctCnt);

    } catch (Exception e) {
        logger.error("Credit XML post: exception parsing response", e);
        outputMap.put("odloanacctcnt", 0);
        outputMap.put("odloanacctcntdetail", "[]");
        outputMap.put("odguaacctcnt", 0);
        outputMap.put("odguaacctcntdetail", "[]");
        outputMap.put("qyzxbgstatuscode", "500");
        outputMap.put("qyzxbgreportid", "");
    }

    return outputMap;
}

private String extractSection(String xml, String tagName) {
    int start = xml.indexOf("<" + tagName + ">");
    if (start < 0) start = xml.indexOf("<" + tagName + " ");
    if (start < 0) return null;
    int end = xml.indexOf("</" + tagName + ">", start);
    if (end < 0) return null;
    return xml.substring(start, end);
}

private String extractTagValue(String xml, String tagName) {
    int start = xml.indexOf("<" + tagName + ">");
    if (start < 0) return null;
    int end = xml.indexOf("</" + tagName + ">", start);
    if (end < 0) return null;
    return xml.substring(start + tagName.length() + 2, end).trim();
}

