                JSONArray searchKeyList = null;
                if (bussMap.containsKey("searchKeyList")) { searchKeyList = JSON.parseArray(bussMap.get("searchKeyList").toString()); }

                //===== Fix2: allParam首次调用可能含原始JSON数组，用listIndex提取实际searchKey =====
                String rawSearchKey = (allParam != null) ? (String) allParam.get("C_S_QCCSEARCHKEYLIST") : null;
                String currentSearchKey = rawSearchKey;
                if (rawSearchKey != null && rawSearchKey.trim().startsWith("[")) {
                    try {
                        JSONArray skArr = JSON.parseArray(rawSearchKey);
                        if (currentIndex < skArr.size()) {
                            currentSearchKey = skArr.getString(currentIndex);
                        }
                    } catch (Exception ignored) {}
                }

                if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                    flag = false;
                    if (searchKeyList != null && currentIndex + 1 < searchKeyList.size()) {
                        int nextIndex = currentIndex + 1;
                        String nextSearchKey = searchKeyList.getString(nextIndex);
                        bussMap.put("listIndex", nextIndex);
                        if (requestInParam != null) {
                            requestInParam.put("C_S_QCCSEARCHKEYLIST", nextSearchKey);
                            requestInParam.put("C_S_PAGEINDEX", "1");
                            etlHandlerContext.setRequestInParam(requestInParam);
                        }
                        flag = true;
                        log.info("740sxhclisthz2:VerifyResult=0,nextIndex={},seq={}", nextIndex, context.getSequenceId());
                    }
                } else {
                    LocalDate today = LocalDate.now();
                    DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);
                            String liandateStr = item.getString("Liandate");
                            if (liandateStr == null || liandateStr.isEmpty()) { continue; }
                            if (liandateStr.length() > 10) { liandateStr = liandateStr.substring(0, 10); }
                            LocalDate liandate = LocalDate.parse(liandateStr, fmt);
                            long daysAgo = ChronoUnit.DAYS.between(liandate, today);
                            if (daysAgo >= 90) { flag = false; break; }
                            accCnt++;
                            JSONObject detailItem = new JSONObject();
                            if (currentSearchKey != null) { detailItem.put("searchKey", currentSearchKey); }
                            String v1 = item.getString("Anno"); if (v1 != null) { detailItem.put("anno", v1); }
                            String v2 = item.getString("Executegov"); if (v2 != null) { detailItem.put("executegov", v2); }
                            String v3 = item.getString("Executestatus"); if (v3 != null) { detailItem.put("executestatus", v3); }
                            String v4 = item.getString("Publicdate"); if (v4 != null) { detailItem.put("publicdate", v4); }
                            String v5 = item.getString("Amount"); if (v5 != null) { detailItem.put("amount", v5); }
                            detailItem.put("liandate", item.getString("Liandate"));
                            accDetail.add(detailItem);
                        }
                    }

                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("740sxhclisthz2-paging:seq={},from={},size={},total={},sk={}", context.getSequenceId(), currentFrom, size, total, currentSearchKey);
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX", String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                flag = true;
                            } else {
                                flag = false;
                            }
                        } else {
                            flag = false;
                        }
                    }

                    if (!flag && searchKeyList != null && searchKeyList.size() > 0) {
                        int nextIndex = currentIndex + 1;
                        if (nextIndex < searchKeyList.size()) {
                            String nextSearchKey = searchKeyList.getString(nextIndex);
                            bussMap.put("listIndex", nextIndex);
                            requestInParam.put("C_S_QCCSEARCHKEYLIST", nextSearchKey);
                            requestInParam.put("C_S_PAGEINDEX", "1");
                            etlHandlerContext.setRequestInParam(requestInParam);
                            flag = true;
                            log.info("740sxhclisthz2:switch nextIndex={},nextSK={},seq={}", nextIndex, nextSearchKey, context.getSequenceId());
                        }
                    }
                }

                bussMap.put("accCnt", accCnt);
                bussMap.put("accDetail", accDetail.toJSONString());
                etlHandlerContext.setBussMap(bussMap);
                context.setEtlHandlerContext(etlHandlerContext);

            } catch (Exception e) {
                flag = false;
                e.printStackTrace();
            }

            outputMap.put("dishonestcnt", accCnt);
            outputMap.put("dishonestcntdetail", accDetail.toJSONString());

        } else {
            //===== Fix1: 非200不再直接截断，保留已累积结果并尝试切换下一个searchKey =====
            flag = false;
            try {
                Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                // 恢复已累积结果（前几个searchKey可能已有数据）
                if (bussMap.containsKey("accCnt")) { accCnt = ((Number) bussMap.get("accCnt")).intValue(); }
                if (bussMap.containsKey("accDetail")) { accDetail = JSON.parseArray(bussMap.get("accDetail").toString()); }
                int currentIndex = 0;
                if (bussMap.containsKey("listIndex")) { currentIndex = ((Number) bussMap.get("listIndex")).intValue(); }
                JSONArray searchKeyList = null;
                if (bussMap.containsKey("searchKeyList")) { searchKeyList = JSON.parseArray(bussMap.get("searchKeyList").toString()); }
                // 尝试切换到下一个searchKey（与VerifyResult=0逻辑对称）
                if (searchKeyList != null && currentIndex + 1 < searchKeyList.size()) {
                    int nextIndex = currentIndex + 1;
                    String nextSearchKey = searchKeyList.getString(nextIndex);
                    bussMap.put("listIndex", nextIndex);
                    if (requestInParam != null) {
                        requestInParam.put("C_S_QCCSEARCHKEYLIST", nextSearchKey);
                        requestInParam.put("C_S_PAGEINDEX", "1");
                        etlHandlerContext.setRequestInParam(requestInParam);
                    }
                    flag = true;
                    log.info("740sxhclisthz2:non-200(status={}) nextIndex={},nextSK={},seq={}", status, nextIndex, nextSearchKey, context.getSequenceId());
                }
                bussMap.put("accCnt", accCnt);
                bussMap.put("accDetail", accDetail.toJSONString());
                etlHandlerContext.setBussMap(bussMap);
                context.setEtlHandlerContext(etlHandlerContext);
            } catch (Exception e) {
                e.printStackTrace();
            }
            // 输出已累积结果（非null），非200的searchKey本身贡献0条
            outputMap.put("dishonestcnt", accCnt);
            outputMap.put("dishonestcntdetail", accDetail.toJSONString());
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[740sxhclisthz2-after]seq:{},ctx:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("740sxhclisthz2-after-end:seq:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("740sxhclisthz2-after-end:seq:{}", context.getSequenceId());
    }
    return outputMap;
}

@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("740sxhclisthz2-sendAfterOnce:seq:{}", context.getSequenceId());
    try {
    } catch (Exception e) {
        log.error("[740sxhclisthz2-sendAfterOnce error]seq:{},cls:{},ctx:{}", context.getSequenceId(),
                this.getClass().getName(), JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect), e);
    }
    log.info("740sxhclisthz2-sendAfterOnce-end:seq:{}", context.getSequenceId());
}

import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerBeforeCaller;
import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.serializer.SerializerFeature;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.security.MessageDigest;
import java.util.HashMap;
import java.util.Map;

/**
 * 740失信核查列表前置ETL（借鉴参考ETL版）：
 * 【Part1 认证签名】每次调用均执行，与 qcctyqzetl 逻辑完全一致。
 * 【Part2 列表初始化】仅首次调用执行（检测到 JSON 数组时）：
 *   解析数组，将 list[0] 写回 urlMap 作为本次请求的 searchKey，
 *   并将完整列表存入 bussMap 供后置ETL使用。
 *   从第2次调用起，requestInParam 中已是后置ETL写入的单值，
 *   startsWith("[") 检查失败，本部分直接跳过。
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerBeforeCaller.class);

@Override
public void afterInitHttpContext(ChannelContext context, HttpContext httpContext) {
    if (log.isDebugEnabled()) {
        log.debug("qcc740sxhclistpre2-afterInitHttpContext-start:sequenceId:{},httpContext{}",
                context.getSequenceId(), JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect));
    } else {
        log.info("qcc740sxhclistpre2-afterInitHttpContext-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        Map<String, Object> urlMap = httpContext.getUrlMap();

        //===== Part1: 认证签名（每次调用，同 qcctyqzetl）=====
        String appKey    = (String) urlMap.get("C_S_QCCAPPKEY");
        String secretKey = (String) urlMap.get("C_S_QCCSECRETKEY");
        String timespan  = String.valueOf(System.currentTimeMillis() / 1000L);
        String rawStr    = (appKey != null ? appKey : "") + timespan + (secretKey != null ? secretKey : "");
        String token     = md5UpperCase(rawStr);
        log.info("qcc740sxhclistpre2:sequenceId:{},timespan={}", context.getSequenceId(), timespan);
        Map<String, Object> headerMap = new HashMap<String, Object>();
        headerMap.put("Token", token);
        headerMap.put("Timespan", timespan);
        httpContext.setHeaders(headerMap);
        urlMap.remove("C_S_QCCSECRETKEY");

        //===== Part2: 列表初始化（仅首次调用，后续调用已是单值直接跳过）=====
        String searchKeyRaw = (String) urlMap.get("C_S_QCCSEARCHKEYLIST");
        if (searchKeyRaw != null && searchKeyRaw.trim().startsWith("[")) {
            JSONArray list = JSON.parseArray(searchKeyRaw);
            if (list != null && !list.isEmpty()) {
                // ★ 先提取 list[0] 写入 urlMap（关键路径，不能被 bussMap 异常中断）
                String firstSearchKey = list.getString(0);
                urlMap.put("C_S_QCCSEARCHKEYLIST", firstSearchKey);
                log.info("qcc740sxhclistpre2:首次调用初始化,listSize={},firstSearchKey={}",
                        list.size(), firstSearchKey);
                // bussMap 初始化（非关键路径，独立 try-catch，失败不影响 searchKey 替换）
                // afterInitHttpContext 阶段 EtlHandlerContext 可能未就绪，需防护 NPE
                try {
                    EtlHandlerContext etlHandlerContext = context.getEtlHandlerContext();
                    if (etlHandlerContext != null) {
                        Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                        bussMap.put("searchKeyList", searchKeyRaw);
                        bussMap.put("listIndex", 0);
                        etlHandlerContext.setBussMap(bussMap);
                        context.setEtlHandlerContext(etlHandlerContext);
                    } else {
                        log.warn("qcc740sxhclistpre2:EtlHandlerContext为null,bussMap初始化跳过,后置ETL将从allParam重建列表");
                    }
                } catch (Exception bussMapEx) {
                    log.warn("qcc740sxhclistpre2:bussMap初始化失败(非致命),firstSearchKey已写入urlMap", bussMapEx);
                }
            }
        }
        // 非数组格式（第2次起后置ETL已写入单值）：直接使用，无需任何处理

        httpContext.setUrlMap(urlMap);
    } catch (Exception e) {
        log.error("[qcc740sxhclistpre2-afterInitHttpContext invoke error]sequenceId:{},className:{},context:{}",
                context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
    }
}

private String md5UpperCase(String input) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] bytes = md.digest(input.getBytes("UTF-8"));
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02X", b & 0xff));
        }
        return sb.toString();
    } catch (Exception e) {
        log.error("md5UpperCase error", e);
        return "";
    }
}

@Override
public void beforeSendHttp(ChannelContext context) {
    log.info("qcc740sxhclistpre2-beforeSendHttp-start:sequenceId:{}", context.getSequenceId());
    try {
    } catch (Exception e) {
        log.error("[qcc740sxhclistpre2-beforeSendHttp invoke error]sequenceId:{},className:{},context:{}",
                context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
    }
}

