/**
 * 740失信核查列表前置ETL（合并版）：
 * 【Part1 认证签名】与 qcctyqzetl 逻辑完全一致：
 *   生成 Timespan/Token 写入 Header，从 urlMap 删除 SecretKey。
 * 【Part2 列表拆分】读取 C_S_QCCSEARCHKEYLIST（JSON数组），
 *   根据 bussMap.listIndex 取当前元素写回 urlMap，
 *   非数组格式则跳过（兼容单值场景）。
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerBeforeCaller.class);

@Override
public void afterInitHttpContext(ChannelContext context, HttpContext httpContext) {
    if (log.isDebugEnabled()) {
        log.debug("qcc740sxhclistpre-afterInitHttpContext-start:sequenceId:{},httpContext{}",
                context.getSequenceId(), JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect));
    } else {
        log.info("qcc740sxhclistpre-afterInitHttpContext-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        Map<String, Object> urlMap = httpContext.getUrlMap();

        //===== Part1: 企查查认证签名（同 qcctyqzetl）=====
