import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import com.alibaba.fastjson.JSON;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.apache.commons.lang3.ObjectUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;
import java.util.Map;

/**
 * 740失信核查列表后置ETL（分页+列表迭代，PAGE）。
 * 在740sxhchz基础上扩展：支持对searchKey列表中每个元素逐一调用并汇总结果。
 * bussMap跟踪：listIndex（当前searchKey索引）、searchKeyList（原始列表JSON）、
 *              accCnt / accDetail（跨searchKey跨分页累计）。
 * detailItem中附加searchKey字段，标识记录归属的查询主体。
 * 输出字段（与740sxhchz完全相同，直接兼容已有规则和字段映射）：
 *   dishonestcnt       : 所有searchKey中近90天失信记录总数
 *   dishonestcntdetail : 全部记录JSONArray（每条附searchKey标签）
 *   statusCode740sxhc  : 最近一次HTTP状态码
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode740sxhc", statusCode);

        boolean flag = true;

        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map<String, String> allParam = null;
        Map<String, String> requestInParam = null;

        try {
            etlHandlerContext = context.getEtlHandlerContext();
            etlRequestResult = etlHandlerContext.getEtlRequestResult();
            allParam = etlRequestResult.getAllParam();
            requestInParam = etlHandlerContext.getRequestInParam();
        } catch (Exception e) {
            flag = false;
            e.printStackTrace();
        }

        int accCnt = 0;
        JSONArray accDetail = new JSONArray();

        if ("200".equals(status)) {

            JSONObject resultObj = responseJson.getJSONObject("Result");

            //===== bussMap跨页跨searchKey状态管理 =====
            try {
                Map<String, Object> bussMap = etlHandlerContext.getBussMap();

                if (bussMap.containsKey("accCnt")) { accCnt = ((Number) bussMap.get("accCnt")).intValue(); }
                if (bussMap.containsKey("accDetail")) { accDetail = JSON.parseArray(bussMap.get("accDetail").toString()); }
                int currentIndex = 0;
                if (bussMap.containsKey("listIndex")) { currentIndex = ((Number) bussMap.get("listIndex")).intValue(); }
                JSONArray searchKeyList = null;
                if (bussMap.containsKey("searchKeyList")) { searchKeyList = JSON.parseArray(bussMap.get("searchKeyList").toString()); }

                // 读新字段名 C_S_QCCSEARCHKEYLIST（pre-ETL已将其替换为当前单值）
                String currentSearchKey = (allParam != null) ? (String) allParam.get("C_S_QCCSEARCHKEYLIST") : null;

                if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                    // 该searchKey无数据，尝试切换到下一个
                    flag = false;
                    if (searchKeyList != null && currentIndex + 1 < searchKeyList.size()) {
                        bussMap.put("listIndex", currentIndex + 1);
                        requestInParam.put("C_S_PAGEINDEX", "1");
                        etlHandlerContext.setRequestInParam(requestInParam);
                        flag = true;
                        log.info("740sxhclisthz:VerifyResult=0,nextIndex={},sequenceId={}",
                                currentIndex + 1, context.getSequenceId());
                    }
                } else {
                    LocalDate today = LocalDate.now();
                    DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);
                            String liandateStr = item.getString("Liandate");
                            if (liandateStr == null || liandateStr.isEmpty()) { continue; }
                            if (liandateStr.length() > 10) { liandateStr = liandateStr.substring(0, 10); }
                            LocalDate liandate = LocalDate.parse(liandateStr, fmt);
                            long daysAgo = ChronoUnit.DAYS.between(liandate, today);
                            // earlyStop：企查查按Liandate倒序，>=90天则后续均超，终止本searchKey翻页
                            if (daysAgo >= 90) {
                                flag = false;
                                break;
                            }
                            accCnt++;
                            JSONObject detailItem = new JSONObject();
                            if (currentSearchKey != null) { detailItem.put("searchKey", currentSearchKey); }
                            String v1 = item.getString("Anno"); if (v1 != null) { detailItem.put("anno", v1); }
                            String v2 = item.getString("Executegov"); if (v2 != null) { detailItem.put("executegov", v2); }
                            String v3 = item.getString("Executestatus"); if (v3 != null) { detailItem.put("executestatus", v3); }
                            String v4 = item.getString("Publicdate"); if (v4 != null) { detailItem.put("publicdate", v4); }
                            String v5 = item.getString("Amount"); if (v5 != null) { detailItem.put("amount", v5); }
                            detailItem.put("liandate", item.getString("Liandate"));
                            accDetail.add(detailItem);
                        }
                    }

                    //===== 分页控制 =====
                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("740sxhclisthz-after:sequenceId:{},from={},size={},total={},searchKey={}",
                                    context.getSequenceId(), currentFrom, size, total, currentSearchKey);
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX",
                                        String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                flag = true;
                            } else {
                                flag = false;
                            }
                        } else {
                            flag = false;
                        }
                    }

                    //===== 列表迭代控制：当前searchKey分页全部完成后切换到下一个 =====
                    if (!flag && searchKeyList != null && searchKeyList.size() > 0) {
                        int nextIndex = currentIndex + 1;
                        if (nextIndex < searchKeyList.size()) {
                            bussMap.put("listIndex", nextIndex);
                            requestInParam.put("C_S_PAGEINDEX", "1");
                            etlHandlerContext.setRequestInParam(requestInParam);
                            flag = true;
                            log.info("740sxhclisthz:switching to nextIndex={},sequenceId={}",
                                    nextIndex, context.getSequenceId());
                        }
                    }
                }

                bussMap.put("accCnt", accCnt);
                bussMap.put("accDetail", accDetail.toJSONString());
                etlHandlerContext.setBussMap(bussMap);
                context.setEtlHandlerContext(etlHandlerContext);

            } catch (Exception e) {
                flag = false;
                e.printStackTrace();
            }

            outputMap.put("dishonestcnt", accCnt);
            outputMap.put("dishonestcntdetail", accDetail.toJSONString());

        } else {
            flag = false;
            outputMap.put("dishonestcnt", null);
            outputMap.put("dishonestcntdetail", new JSONArray().toJSONString());
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[740sxhclisthz-after]sequenceId:{},context:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("ICustomEtlHandlerAfterCaller-sendAfterOnce-start:sequenceId:{}", context.getSequenceId());
    try {
    } catch (Exception e) {
        log.error("[ICustomEtlHandlerAfterCaller-sendAfterOnce invoke error]sequenceId:{},className:{},httpContext:{},",
                context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect), e);
    }
    log.info("ICustomEtlHandlerAfterCaller-sendAfterOnce-end:sequenceId:{}", context.getSequenceId());
}

import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.apache.commons.lang3.ObjectUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;
import java.util.Map;

/**
 * 255资质证书后置ETL（分页 PAGE，无早停）。
 *
 * 本版按企查查740标准分页结构调整：
 * 1. context / allParam / requestInParam 获取失败时，只停止后续翻页，不中断当前页业务解析；
 * 2. 当前页 Result 始终优先解析，确保 mock / 单页测试也能输出业务字段；
 * 3. 跨页状态使用 bussMap；
 * 4. 分页逻辑放在业务逻辑之后，仅在 flag=true 时执行。
 *
 * quallevel 输出完整资质名称列表，例如：
 * 建筑工程施工总承包一级，市政公用工程施工总承包二级
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();

    if (log.isDebugEnabled()) {
        log.debug("255zzzs-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("255zzzs-after-start:sequenceId:{}", context.getSequenceId());
    }

    try {
        JSONObject responseJson = JSON.parseObject(response);

        boolean flag = true;

        String status = responseJson.getString("Status");
        int statusCode = parseStatusCode(status);
        outputMap.put("statusCode255zzzs", statusCode);

        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map allParam = null;
        Map requestInParam = null;

        if ("200".equals(status)) {
            /*
             * 标准分页写法：上下文获取失败只影响翻页，不影响当前页业务解析。
             * mock测试时 etlRequestResult 可能为空，这里不能直接让 after 失败。
             */
            try {
                etlHandlerContext = context.getEtlHandlerContext();
                etlRequestResult = etlHandlerContext.getEtlRequestResult();
                allParam = etlRequestResult.getAllParam();
                requestInParam = etlHandlerContext.getRequestInParam();
            } catch (Exception e) {
                flag = false;
                log.error("[255zzzs-context-error]sequenceId:{},message:{}",
                        context.getSequenceId(), e.getMessage(), e);
            }

            boolean hasMatched = false;
            Long minPosDays = null;
            Long maxNegDays = null;
            JSONArray qualNames = new JSONArray();
            JSONArray abnormalStatuses = new JSONArray();

            /*
             * 恢复跨页累计状态。
             * 如果上下文不可用，则按单页处理，不影响 mock 测试输出。
             */
            try {
                if (etlHandlerContext != null) {
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    if (bussMap != null) {
                        if (bussMap.containsKey("hasMatched")) {
                            hasMatched = (Boolean) bussMap.get("hasMatched");
                        }
                        if (bussMap.containsKey("minPosDays")) {
                            minPosDays = ((Number) bussMap.get("minPosDays")).longValue();
                        }
                        if (bussMap.containsKey("maxNegDays")) {
                            maxNegDays = ((Number) bussMap.get("maxNegDays")).longValue();
                        }
                        if (bussMap.containsKey("qualNames")) {
                            qualNames = JSON.parseArray(String.valueOf(bussMap.get("qualNames")));
                        }
                        if (bussMap.containsKey("abnormalStatuses")) {
                            abnormalStatuses = JSON.parseArray(String.valueOf(bussMap.get("abnormalStatuses")));
                        }
                    }
                }
            } catch (Exception e) {
                flag = false;
                log.error("[255zzzs-bussmap-read-error]sequenceId:{},message:{}",
                        context.getSequenceId(), e.getMessage(), e);
            }

            /*
             * 业务处理：当前页 Result 解析。
             */
            JSONArray resultArray = responseJson.getJSONArray("Result");
            if (resultArray != null) {
                LocalDate today = LocalDate.now();
                DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                for (int i = 0; i < resultArray.size(); i++) {
                    JSONObject item = resultArray.getJSONObject(i);
                    if (item == null) {
                        continue;
                    }

                    String name = item.getString("Name");
                    if (!isQualRelated(name)) {
                        continue;
                    }

                    hasMatched = true;
                    addIfAbsent(qualNames, name);

                    String endDateStr = item.getString("EndDate");
                    if (endDateStr != null && endDateStr.length() > 0) {
                        if (endDateStr.length() > 10) {
                            endDateStr = endDateStr.substring(0, 10);
                        }
                        try {
                            LocalDate endDate = LocalDate.parse(endDateStr, fmt);
                            long days = ChronoUnit.DAYS.between(today, endDate);
                            if (days >= 0) {
                                if (minPosDays == null || days < minPosDays) {
                                    minPosDays = days;
                                }
                            } else {
                                if (maxNegDays == null || days > maxNegDays) {
                                    maxNegDays = days;
                                }
                            }
                        } catch (Exception ignored) {
                            // 单条日期异常不影响整页解析。
                        }
                    }

                    String certStatus = item.getString("Status");
                    if (certStatus != null
                            && (certStatus.contains("吊销") || certStatus.contains("撤销") || certStatus.contains("注销"))) {
                        addIfAbsent(abnormalStatuses, certStatus);
                    }
                }
            }

            /*
             * 写回跨页状态。
             * 写回失败只停止翻页，不覆盖当前页已解析出的 outputMap。
             */
            try {
                if (etlHandlerContext != null) {
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    if (bussMap == null) {
                        bussMap = Maps.newHashMap();
                    }

                    bussMap.put("hasMatched", hasMatched);
                    if (minPosDays != null) {
                        bussMap.put("minPosDays", minPosDays);
                    }
                    if (maxNegDays != null) {
                        bussMap.put("maxNegDays", maxNegDays);
                    }
                    bussMap.put("qualNames", qualNames.toJSONString());
                    bussMap.put("abnormalStatuses", abnormalStatuses.toJSONString());

                    etlHandlerContext.setBussMap(bussMap);
                    context.setEtlHandlerContext(etlHandlerContext);
                }
            } catch (Exception e) {
                flag = false;
                log.error("[255zzzs-bussmap-write-error]sequenceId:{},message:{}",
                        context.getSequenceId(), e.getMessage(), e);
            }

            /*
             * 每页都输出截至当前页的累计结果。
             * 最后一页 after() 的 outputMap 即最终结果。
             */
            fillCurrentOutput(outputMap, hasMatched, qualNames, minPosDays, maxNegDays, abnormalStatuses);

            /*
             * 标准分页逻辑区域：只有上下文获取成功且业务未要求停止时才尝试翻页。
             */
            try {
                if (flag) {
                    JSONObject pagingObject = responseJson.getJSONObject("Paging");
                    if (pagingObject != null) {
                        Integer total = pagingObject.getIntValue("TotalRecords");

                        String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX"))
                                ? "1"
                                : String.valueOf(allParam.get("C_S_PAGEINDEX"));

                        String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                || "0".equals(String.valueOf(allParam.get("C_S_PAGESIZE")))
                                ? "20"
                                : String.valueOf(allParam.get("C_S_PAGESIZE"));

                        log.info("255zzzs-after-page:sequenceId:{},from={},size={},total={}",
                                context.getSequenceId(), currentFrom, size, total);

                        int totalPage = divideRoundUp(total, Integer.parseInt(size));

                        if (Integer.valueOf(currentFrom) < totalPage) {
                            String currentFromAdd = String.valueOf(Integer.parseInt(currentFrom) + 1);
                            requestInParam.put("C_S_PAGEINDEX", currentFromAdd);
                            etlHandlerContext.setRequestInParam(requestInParam);
                            context.setEtlHandlerContext(etlHandlerContext);
                            flag = true;

                            log.info("255zzzs-after-page-next:sequenceId:{},nextPage={}",
                                    context.getSequenceId(), currentFromAdd);
                        } else {
                            flag = false;
                        }
                    } else {
                        flag = false;
                    }
                }
            } catch (Exception e) {
                flag = false;
                log.error("[255zzzs-pagination-error]sequenceId:{},message:{}",
                        context.getSequenceId(), e.getMessage(), e);
            }
        } else {
            flag = false;
            putDefaultBusinessOutput(outputMap);
        }

        context.setPageNextLoop(flag);
    } catch (Exception e) {
        putDefaultAllOutput(outputMap);
        context.setPageNextLoop(false);
        log.error("[255zzzs-after-error]sequenceId:{},context:{}",
                context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect),
                e);
    }

    log.info("255zzzs-after-end:sequenceId:{}", context.getSequenceId());
    return outputMap;
}

private void fillCurrentOutput(Map<String, Object> outputMap, boolean hasMatched, JSONArray qualNames,
                               Long minPosDays, Long maxNegDays, JSONArray abnormalStatuses) {
    if (!hasMatched) {
        putDefaultBusinessOutput(outputMap);
        return;
    }

    outputMap.put("quallevel", joinByChineseComma(qualNames));

    long qualExpDays = 0L;
    if (minPosDays != null) {
        qualExpDays = minPosDays;
    } else if (maxNegDays != null) {
        qualExpDays = maxNegDays;
    }
    outputMap.put("qualexpdays", qualExpDays);

    if (abnormalStatuses != null && !abnormalStatuses.isEmpty()) {
        outputMap.put("qualstatus", joinBySlash(abnormalStatuses));
    } else {
        outputMap.put("qualstatus", "正常");
    }
}

private void putDefaultBusinessOutput(Map<String, Object> outputMap) {
    outputMap.put("quallevel", "");
    outputMap.put("qualexpdays", 0L);
    outputMap.put("qualstatus", "");
}

private void putDefaultAllOutput(Map<String, Object> outputMap) {
    if (!outputMap.containsKey("statusCode255zzzs")) {
        outputMap.put("statusCode255zzzs", 0);
    }
    putDefaultBusinessOutput(outputMap);
}

private boolean isQualRelated(String name) {
    if (name == null || name.length() == 0) {
        return false;
    }
    return name.contains("建设") || name.contains("工程") || name.contains("资质")
            || name.contains("监理") || name.contains("勘察") || name.contains("设计");
}

private void addIfAbsent(JSONArray array, String value) {
    if (value == null || value.length() == 0) {
        return;
    }
    for (int i = 0; i < array.size(); i++) {
        if (value.equals(array.getString(i))) {
            return;
        }
    }
    array.add(value);
}

private String joinByChineseComma(JSONArray array) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < array.size(); i++) {
        if (i > 0) {
            sb.append("，");
        }
        sb.append(array.getString(i));
    }
    return sb.toString();
}

private String joinBySlash(JSONArray array) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < array.size(); i++) {
        if (i > 0) {
            sb.append("/");
        }
        sb.append(array.getString(i));
    }
    return sb.toString();
}

private int parseStatusCode(String value) {
    try {
        if (value == null || value.trim().length() == 0) {
            return 0;
        }
        return Integer.parseInt(value.trim());
    } catch (Exception e) {
        return 0;
    }
}

/**
 * 向上取整计算总页数，避免 BigDecimal.divide 不能整除时抛 ArithmeticException。
 */
private int divideRoundUp(int total, int size) {
    if (size <= 0) {
        throw new IllegalArgumentException("page size must be positive");
    }
    if (total <= 0) {
        return 0;
    }
    return (total + size - 1) / size;
}

@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("255zzzs-sendAfterOnce-start:sequenceId:{}", context.getSequenceId());
    try {
        // 当前后置ETL无需在单次HTTP调用后额外处理。
    } catch (Exception e) {
        log.error("[255zzzs-sendAfterOnce-error]sequenceId:{},className:{},httpContext:{}",
                context.getSequenceId(),
                this.getClass().getName(),
                JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect),
                e);
    }
    log.info("255zzzs-sendAfterOnce-end:sequenceId:{}", context.getSequenceId());
}

import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import com.alibaba.fastjson.JSON;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.apache.commons.lang3.ObjectUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;
import java.util.Map;

/**
 * 958招投标信息后置ETL（分页，PAGE，earlyStop=true）。
 * 接口响应结构: {"Status":"200","Paging":{...},"Result":{"VerifyResult":1,"Data":[{...}]}}
 * 入参: keyword=企业名称，msgType=4（中标公告），DS层已配置；API按PublishDate降序返回。
 * earlyStop：遇PublishDate早于12个月前的记录即flag=false终止翻页（后续记录更旧）。
 *
 * 处理逻辑（跨页累计）：
 *   1. 读Status → statusCode958zzbxx；非200终止分页
 *   2. VerifyResult=0时停止翻页，输出空结果
 *   3. 遍历Data数组，过滤PublishDate在近12个月内的记录
 *   4. 提取每条记录: projectname/projectcode/publishdate/winamount/purchaser/winunit
 *   5. bidinfo=记录总数字符串，bidinfodetail=明细JSONArray字符串
 *
 * 输出字段:
 *   bidinfo:            近12个月内中标记录数（字符串形式，如"5"）
 *   bidinfodetail:      中标信息明细JSONArray字符串
 *   statusCode958zzbxx: 接口HTTP状态码
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出，供规则判断接口是否正常返回
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode958zzbxx", statusCode);

        // flag默认true（激进策略：默认继续翻页，在终止条件下置false）
        boolean flag = true;

        // 上下文对象延迟声明为null（防御性：status非200时无需获取）
        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map<String, String> allParam = null;       // allParam：含所有入参展开值，key=DS字段名
        Map<String, String> requestInParam = null; // requestInParam：可写入下一页入参

        if ("200".equals(status)) {

            //===== 上下文获取：独立try-catch，获取失败则停止翻页 =====
            try {
                etlHandlerContext = context.getEtlHandlerContext();
                etlRequestResult = etlHandlerContext.getEtlRequestResult();
                allParam = etlRequestResult.getAllParam();
                requestInParam = etlHandlerContext.getRequestInParam();
            } catch (Exception e) {
                flag = false; // 上下文获取失败，终止翻页
                e.printStackTrace();
            }

            //===== 业务处理 =====
            JSONObject resultObj = responseJson.getJSONObject("Result");
            if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                // VerifyResult=0：无数据，停止翻页
                flag = false;
                outputMap.put("bidinfo", "0");
                outputMap.put("bidinfodetail", new JSONArray().toJSONString());
            } else {

                LocalDate today = LocalDate.now();
                LocalDate twelveMonthsAgo = today.minusMonths(12); // 12个月截止日
                DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                // 累计变量在bussMap try-catch外声明（保证bussMap异常时仍有输出）
                JSONArray accDetail = new JSONArray();

                //===== bussMap跨页状态操作：独立try-catch =====
                try {
                    // bussMap：平台原生跨页状态容器，同一请求多次after()间共享，平台管理生命周期
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    // 恢复上一页写入的累计状态（首页时bussMap为空，使用上方声明的初始值）
                    if (bussMap.containsKey("accDetail")) { accDetail = JSON.parseArray(bussMap.get("accDetail").toString()); }

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);
                            if (item == null) { continue; }

                            // 12个月日期过滤；API按PublishDate降序，早于12个月前则后续均超，earlyStop
                            String pubDateStr = item.getString("PublishDate");
                            if (pubDateStr != null && !pubDateStr.isEmpty()) {
                                try {
                                    String pd = pubDateStr.length() > 10 ? pubDateStr.substring(0, 10) : pubDateStr;
                                    LocalDate pubDate = LocalDate.parse(pd, fmt);
                                    if (pubDate.isBefore(twelveMonthsAgo)) {
                                        flag = false; // earlyStop：已超12个月，后续记录更旧，终止翻页
                                        break;
                                    }
                                } catch (Exception ex) {
                                    // 日期解析失败则保留（宽容处理，不参与earlyStop）
                                }
                            }

                            JSONObject detailItem = new JSONObject();

                            // 项目名称
                            String title = item.getString("Title");
                            detailItem.put("projectname", title != null ? title : "");

                            // 项目编号
                            String projectNo = item.getString("ProjectNo");
                            detailItem.put("projectcode", projectNo != null ? projectNo : "");

                            // 发布时间
                            String publishDate = item.getString("PublishDate");
                            detailItem.put("publishdate", publishDate != null ? publishDate : "");

                            // 中标金额：从WinBidUnitList[0].WinBidAmt取；无则从BudgetAmt取预算金额备用
                            String winAmt = "";
                            JSONArray winBidUnitList = item.getJSONArray("WinBidUnitList");
                            if (winBidUnitList != null && !winBidUnitList.isEmpty()) {
                                JSONObject winUnit0 = winBidUnitList.getJSONObject(0);
                                if (winUnit0 != null) {
                                    String amt = winUnit0.getString("WinBidAmt");
                                    if (amt != null && !amt.isEmpty()) { winAmt = amt; }
                                }
                            }
                            if (winAmt.isEmpty()) {
                                String budgetAmt = item.getString("BudgetAmt");
                                winAmt = (budgetAmt != null) ? budgetAmt : "";
                            }
                            detailItem.put("winamount", winAmt);

                            // 采购/招标单位：从BidInviUnitList[0].Name取
                            String purchaser = "";
                            JSONArray bidInviUnitList = item.getJSONArray("BidInviUnitList");
                            if (bidInviUnitList != null && !bidInviUnitList.isEmpty()) {
                                JSONObject invitUnit0 = bidInviUnitList.getJSONObject(0);
                                if (invitUnit0 != null) {
                                    String unitName = invitUnit0.getString("Name");
                                    if (unitName != null && !unitName.isEmpty()) { purchaser = unitName; }
                                }
                            }
                            detailItem.put("purchaser", purchaser);

                            // 中标单位名称：从WinBidUnitList[0].Name取
                            String winUnitName = "";
                            if (winBidUnitList != null && !winBidUnitList.isEmpty()) {
                                JSONObject winUnit0 = winBidUnitList.getJSONObject(0);
                                if (winUnit0 != null) {
                                    String name = winUnit0.getString("Name");
                                    if (name != null && !name.isEmpty()) { winUnitName = name; }
                                }
                            }
                            detailItem.put("winunit", winUnitName);

                            accDetail.add(detailItem);
                        }
                    }

                    // 写回跨页状态（平台管理生命周期）
                    bussMap.put("accDetail", accDetail.toJSONString());
                    etlHandlerContext.setBussMap(bussMap);
                    context.setEtlHandlerContext(etlHandlerContext); // 仅在setBussMap后调用一次

                } catch (Exception e) {
                    flag = false; // bussMap操作异常，停止翻页
                    e.printStackTrace();
                }

                // 输出当前累计结果（最后一页调用时的值即为最终结果）
                log.info("958zzbxxhz-after:sequenceId:{},bidinfo={}", context.getSequenceId(), accDetail.size());
                outputMap.put("bidinfo", String.valueOf(accDetail.size()));
                outputMap.put("bidinfodetail", accDetail.toJSONString());

                //===== 分页控制：在业务处理之后、独立try-catch =====
                try {
                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("958zzbxxhz-after:sequenceId:{},from={},size={},total={}",
                                    context.getSequenceId(), currentFrom, size, total);
                            // ceil(total/size)：2参数divide + setScale（与参考实现一致）
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX",
                                        String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                // setRequestInParam后不再重复调用context.setEtlHandlerContext（已在setBussMap时调用）
                                flag = true;
                                log.info("958zzbxxhz-after:sequenceId:{},context={}",
                                        context.getSequenceId(), JSON.toJSONString(context));
                            } else {
                                flag = false; // 已是最后一页
                            }
                        } else {
                            flag = false; // Paging节点缺失
                        }
                    }
                } catch (Exception e) {
                    flag = false; // 分页计算异常，停止翻页
                    e.printStackTrace();
                }
            }
        } else {
            // 非200状态，终止翻页，写默认值
            flag = false;
            outputMap.put("bidinfo", "0");
            outputMap.put("bidinfodetail", new JSONArray().toJSONString());
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[958zzbxxhz-after]sequenceId:{},context:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

