import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import com.alibaba.fastjson.JSON;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.apache.commons.lang3.ObjectUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;
import java.util.Map;

/**
 * 742限制高消费核查后置ETL（分页，PAGE）。
 * 企查查按JudgeDate倒序返回，earlyStop=true：遇超90天记录即flag=false终止翻页。
 * 过滤条件：JudgeDate距今<90天。
 * 跨页状态：使用etlHandlerContext.getBussMap()累计count和detail。
 * 输出字段：
 *   highconsumecnt: 近90天限制高消费案件数
 *   highconsumecntdetail: 案件详情JSONArray[{caseno,judgdate,personname,companyname,applicant,amount}]
 *   statusCode742xzgxfhc: 接口HTTP状态码，200=成功
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出，供规则判断接口是否正常返回
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode742xzgxfhc", statusCode);

        // flag默认true（激进策略：默认继续翻页，在终止条件下置false）
        boolean flag = true;

        // 上下文对象延迟声明为null（防御性：status非200时无需获取）
        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map<String, String> allParam = null;       // allParam：含所有入参展开值，key=DS字段名（如C_S_PAGEINDEX），用于读取当前页码
        Map<String, String> requestInParam = null; // requestInParam：可写入下一页入参，平台在下次调用时读取

        if ("200".equals(status)) {

            //===== 上下文获取：独立try-catch，获取失败则停止翻页 =====
            try {
                etlHandlerContext = context.getEtlHandlerContext();
                etlRequestResult = etlHandlerContext.getEtlRequestResult();
                allParam = etlRequestResult.getAllParam();
                requestInParam = etlHandlerContext.getRequestInParam();
            } catch (Exception e) {
                flag = false; // 上下文获取失败，终止翻页
                e.printStackTrace();
            }

            //===== 业务处理 =====
            JSONObject resultObj = responseJson.getJSONObject("Result");
            if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                // VerifyResult=0：无数据，显式置flag=false
                flag = false;
                outputMap.put("highconsumecnt", 0);
                outputMap.put("highconsumecntdetail", new JSONArray().toJSONString());
            } else {

                LocalDate today = LocalDate.now();
                DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                // 累计变量在bussMap try-catch外声明（保证bussMap异常时仍有输出）
                int accCnt = 0;
                JSONArray accDetail = new JSONArray();

                //===== bussMap跨页状态操作：独立try-catch =====
                try {
                    // bussMap：平台原生跨页状态容器，同一请求多次after()间共享，平台管理生命周期
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    // 恢复上一页写入的累计状态（首页时bussMap为空，使用上方声明的初始值）
                    if (bussMap.containsKey("accCnt")) { accCnt = ((Number) bussMap.get("accCnt")).intValue(); }
                    if (bussMap.containsKey("accDetail")) { accDetail = JSON.parseArray(bussMap.get("accDetail").toString()); }

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);

                            // 读取JudgeDate，取前10字符（yyyy-MM-dd），兼容"yyyy-MM-dd HH:mm:ss"格式
                            String judgeDateStr = item.getString("JudgeDate");
                            if (judgeDateStr == null || judgeDateStr.isEmpty()) {
                                continue; // 无日期记录跳过
                            }
                            if (judgeDateStr.length() > 10) {
                                judgeDateStr = judgeDateStr.substring(0, 10);
                            }
                            LocalDate judgeDate = LocalDate.parse(judgeDateStr, fmt);
                            long daysAgo = ChronoUnit.DAYS.between(judgeDate, today);

                            // earlyStop：企查查按倒序返回，遇超90天记录则后续均超，flag=false并终止循环
                            if (daysAgo >= 90) {
                                flag = false;
                                break;
                            }

                            // 符合过滤条件，累计计入
                            accCnt++;
                            JSONObject detailItem = new JSONObject();
                            String v1 = item.getString("CaseNo"); if (v1 != null) { detailItem.put("caseno", v1); }           // 案号
                            String v2 = item.getString("JudgeDate"); if (v2 != null) { detailItem.put("judgedate", v2); }     // 立案日期
                            String v3 = item.getString("PersonName"); if (v3 != null) { detailItem.put("personname", v3); }   // 关联对象
                            String v4 = item.getString("CompanyName"); if (v4 != null) { detailItem.put("companyname", v4); } // 限制令对象
                            String v5 = item.getString("Applicant"); if (v5 != null) { detailItem.put("applicant", v5); }     // 申请人
                            String v6 = item.getString("Amount"); if (v6 != null) { detailItem.put("amount", v6); }           // 涉案金额
                            accDetail.add(detailItem);
                        }
                    }

                    // 写回跨页状态（平台管理生命周期，无需手动清理）
                    bussMap.put("accCnt", accCnt);
                    bussMap.put("accDetail", accDetail.toJSONString());
                    etlHandlerContext.setBussMap(bussMap);
                    context.setEtlHandlerContext(etlHandlerContext); // 仅在setBussMap后调用一次

                } catch (Exception e) {
                    flag = false; // bussMap操作异常，停止翻页
                    e.printStackTrace();
                }

                // 输出在bussMap try-catch外（保证bussMap失败时仍有默认输出）
                outputMap.put("highconsumecnt", accCnt);
                outputMap.put("highconsumecntdetail", accDetail.toJSONString());

                //===== 分页控制：在业务处理之后、独立try-catch =====
                try {
                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("742xzgxfhc-after:sequenceId:{},from={},size={},total={}",
                                    context.getSequenceId(), currentFrom, size, total);
                            // ceil(total/size)：2参数divide + setScale（与参考实现一致）
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX",
                                        String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                // setRequestInParam后不再调用context.setEtlHandlerContext（已在setBussMap时调用）
                                flag = true;
                                log.info("742xzgxfhc-after:sequenceId:{},context={}",
                                        context.getSequenceId(), JSON.toJSONString(context));
                            } else {
                                flag = false; // 已是最后一页
                            }
                        } else {
                            flag = false; // Paging节点缺失
                        }
                    }
                } catch (Exception e) {
                    flag = false; // 分页计算异常，停止翻页
                    e.printStackTrace();
                }
            }
        } else {
            // 非200状态，终止翻页
            flag = false;
            outputMap.put("highconsumecnt", 0);
            outputMap.put("highconsumecntdetail", new JSONArray().toJSONString());
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[742xzgxfhc-after]sequenceId:{},context:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

/**
 * 单次Http调用之后的处理逻辑
 *
 * @param context     全局上下文
 * @param httpContext 参数信息
 */
@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("ICustomEtlHandlerAfterCaller-sendAfterOnce-start:sequenceId:{}", context.getSequenceId());
    try {
    // 此处编写自定义代码
    } catch (Exception e) {
        log.error("[ICustomEtlHandlerAfterCaller-sendAfterOnce invoke error]sequenceId:{},className:{},httpContext:{},", context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect), e);
    }
    log.info("ICustomEtlHandlerAfterCaller-sendAfterOnce-end:sequenceId:{}", context.getSequenceId());
}

import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import com.alibaba.fastjson.JSON;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.apache.commons.lang3.ObjectUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * 744司法拍卖核查后置ETL（分页，PAGE）。
 * 企查查按ActionRemark日期倒序返回，earlyStop=true：遇超90天记录即flag=false终止翻页。
 * 过滤条件：ActionRemark（拍卖时间）距今<90天。
 * ActionRemark为中文时间范围字符串，如"2019年11月11日上午10时至2019年11月12日上午10时止"，
 * 使用正则 (\d{4})年(\d{1,2})月(\d{1,2})日 提取起始日期，无法匹配则跳过该记录。
 * 跨页状态：使用etlHandlerContext.getBussMap()累计count和detail。
 * 输出字段：
 *   judicialauctioncnt: 近90天司法拍卖案件数
 *   judicialauctioncntdetail: 案件详情JSONArray[{name,caseno,executegov,actionremark,yiwu,evaluationprice}]
 *   statusCode744sfpmhc: 接口HTTP状态码，200=成功
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出，供规则判断接口是否正常返回
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode744sfpmhc", statusCode);

        // flag默认true（激进策略：默认继续翻页，在终止条件下置false）
        boolean flag = true;

        // 上下文对象延迟声明为null（防御性：status非200时无需获取）
        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map<String, String> allParam = null;       // allParam：含所有入参展开值，key=DS字段名（如C_S_PAGEINDEX），用于读取当前页码
        Map<String, String> requestInParam = null; // requestInParam：可写入下一页入参，平台在下次调用时读取

        if ("200".equals(status)) {

            //===== 上下文获取：独立try-catch，获取失败则停止翻页 =====
            try {
                etlHandlerContext = context.getEtlHandlerContext();
                etlRequestResult = etlHandlerContext.getEtlRequestResult();
                allParam = etlRequestResult.getAllParam();
                requestInParam = etlHandlerContext.getRequestInParam();
            } catch (Exception e) {
                flag = false; // 上下文获取失败，终止翻页
                e.printStackTrace();
            }

            //===== 业务处理 =====
            JSONObject resultObj = responseJson.getJSONObject("Result");
            if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                // VerifyResult=0：无数据，显式置flag=false
                flag = false;
                outputMap.put("judicialauctioncnt", 0);
                outputMap.put("judicialauctioncntdetail", new JSONArray().toJSONString());
            } else {

                LocalDate today = LocalDate.now();
                DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                // 累计变量在bussMap try-catch外声明（保证bussMap异常时仍有输出）
                int accCnt = 0;
                JSONArray accDetail = new JSONArray();

                //===== bussMap跨页状态操作：独立try-catch =====
                try {
                    // bussMap：平台原生跨页状态容器，同一请求多次after()间共享，平台管理生命周期
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    // 恢复上一页写入的累计状态（首页时bussMap为空，使用上方声明的初始值）
                    if (bussMap.containsKey("accCnt")) { accCnt = ((Number) bussMap.get("accCnt")).intValue(); }
                    if (bussMap.containsKey("accDetail")) { accDetail = JSON.parseArray(bussMap.get("accDetail").toString()); }

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    // 中文日期正则：提取 ActionRemark 中的起始日期（如"2019年11月11日上午10时至..."）
                    Pattern cnDatePattern = Pattern.compile("(\\d{4})年(\\d{1,2})月(\\d{1,2})日");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);

                            // 读取ActionRemark，格式为中文时间范围如"2019年11月11日上午10时至2019年11月12日上午10时止"
                            // 使用正则提取起始日期，而非直接截取前10字符（那样会得到"2019年11月1"，无法解析为yyyy-MM-dd）
                            String actionRemarkStr = item.getString("ActionRemark");
                            if (actionRemarkStr == null || actionRemarkStr.isEmpty()) {
                                continue; // 无拍卖时间记录，跳过
                            }
                            Matcher m = cnDatePattern.matcher(actionRemarkStr);
                            if (!m.find()) {
                                continue; // 无法从ActionRemark中提取日期，跳过（不参与earlyStop判断）
                            }
                            // 构造标准日期字符串 yyyy-MM-dd
                            String year  = m.group(1);
                            String month = String.format("%02d", Integer.parseInt(m.group(2)));
                            String day   = String.format("%02d", Integer.parseInt(m.group(3)));
                            LocalDate actionDate;
                            try {
                                actionDate = LocalDate.parse(year + "-" + month + "-" + day, fmt);
                            } catch (Exception ex) {
                                continue; // 日期值非法，跳过
                            }
                            long daysAgo = ChronoUnit.DAYS.between(actionDate, today);

                            // earlyStop：企查查按倒序返回，遇超90天记录则后续均超，flag=false并终止循环
                            if (daysAgo >= 90) {
                                flag = false;
                                break;
                            }

                            // 符合过滤条件，累计计入
                            accCnt++;
                            JSONObject detailItem = new JSONObject();
                            String v1 = item.getString("Name"); if (v1 != null) { detailItem.put("name", v1); }                         // 标题
                            String v2 = item.getString("CaseNo"); if (v2 != null) { detailItem.put("caseno", v2); }                     // 案号
                            String v3 = item.getString("Executegov"); if (v3 != null) { detailItem.put("executegov", v3); }             // 处置单位
                            String v4 = item.getString("ActionRemark"); if (v4 != null) { detailItem.put("actionremark", v4); }         // 拍卖时间
                            String v5 = item.getString("YiWu"); if (v5 != null) { detailItem.put("yiwu", v5); }                         // 起拍价
                            String v6 = item.getString("EvaluationPrice"); if (v6 != null) { detailItem.put("evaluationprice", v6); }   // 评估价
                            accDetail.add(detailItem);
                        }
                    }

                    // 写回跨页状态（平台管理生命周期，无需手动清理）
                    bussMap.put("accCnt", accCnt);
                    bussMap.put("accDetail", accDetail.toJSONString());
                    etlHandlerContext.setBussMap(bussMap);
                    context.setEtlHandlerContext(etlHandlerContext); // 仅在setBussMap后调用一次

                } catch (Exception e) {
                    flag = false; // bussMap操作异常，停止翻页
                    e.printStackTrace();
                }

                // 输出在bussMap try-catch外（保证bussMap失败时仍有默认输出）
                outputMap.put("judicialauctioncnt", accCnt);
                outputMap.put("judicialauctioncntdetail", accDetail.toJSONString());

                //===== 分页控制：在业务处理之后、独立try-catch =====
                try {
                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("744sfpmhc-after:sequenceId:{},from={},size={},total={}",
                                    context.getSequenceId(), currentFrom, size, total);
                            // ceil(total/size)：2参数divide + setScale（与参考实现一致）
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX",
                                        String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                // setRequestInParam后不再调用context.setEtlHandlerContext（已在setBussMap时调用）
                                flag = true;
                                log.info("744sfpmhc-after:sequenceId:{},context={}",
                                        context.getSequenceId(), JSON.toJSONString(context));
                            } else {
                                flag = false; // 已是最后一页
                            }
                        } else {
                            flag = false; // Paging节点缺失
                        }
                    }
                } catch (Exception e) {
                    flag = false; // 分页计算异常，停止翻页
                    e.printStackTrace();
                }
            }
        } else {
            // 非200状态，终止翻页
            flag = false;
            outputMap.put("judicialauctioncnt", 0);
            outputMap.put("judicialauctioncntdetail", new JSONArray().toJSONString());
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[744sfpmhc-after]sequenceId:{},context:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

