/**
 * 2003客户身份识别后置ETL（普通，非分页COMMON，超复杂6模块）。
 * 接口地址: https://api.qichacha.com/CustomerDueDiligence/KYC
 * 接口响应: {"Status":"200","Result":{"VerifyResult":1,"Data":{...}}}
 * 注意: Data是Object（非数组），内含ChangeList/RevokeInfo/TaxCreditList/PubPartnerList/InvestmentList等子结构。
 *
 * 【模块1: ChangeList变更信息】
 *   筛选ChangeDate距今<90天的变更记录，按ProjectName分类：
 *   - 含"法定代表" → 法定代表人变更记录数量(chglegalrepcnt) + 详情(chglegalrepcntdetail)
 *   - 含投资人/股东/股权/股份转让/出资比例/出资额/出资情况变更 → 股权变更(chgequitycnt) + 详情(ent3mequitychangedetailqcc)
 *   - 含经营范围/主营范围/业务范围/兼营范围/辅营经营范围 → 经营范围变更(chgscopecnt) + 详情(chgscopecntdetail)
 *   - 含"注册资本" → 提取BeforeList/AfterList金额，判断增/减资：
 *       变更后<变更前 → 减资记录(capdeccnt) + 详情(ent3mregcapdecreasechangedetailqcc) + 减资比例(capdecratio)
 *       变更后>变更前 → 增资记录(capinccnt) + 详情(ent3mregcapincreasechangedetailqcc)
 *
 * 【模块2: Data企业工商信息（Data对象本身字段）】
 *   RegistCapi → 注册资本(regcap, 元，去除文字)
 *   RealCapi   → 实缴资本(paidcap, 元，去除文字)
 *   RealCapi/RegistCapi → 实缴比例(paidcapratio)
 *   StartDate  → 成立日期(estabdate, DATE类型，yyyy-MM-dd)
 *
 * 【模块3: RevokeInfo注销吊销信息】
 *   RevokeInfo是Data对象内的子对象（非数组）；
 *   检查CancelDate或RevokeDate距今<90天 → revokecnt(0或1) + 详情(revokecntdetail)
 *   关联企业近3个月注销吊销（relatedent3mcancelrevokecountqcc/detail）：本接口无关联企业数据，输出0/空。
 *
 * 【模块4: TaxCreditList纳税信用等级】
 *   取Year字段最大（最新）的那条记录的Level值 → taxcreditgrade
 *
 * 【模块5: PubPartnerList最新公示股东信息（中间变量）】
 *   筛选StockPercent>20%的记录，去重后存储CreditCode（作为后续调用740失信核查的标识）列表：
 *   pdishonestflag: 符合条件的股东数（非失信数，由下游740决定，此处输出列表长度）
 *   shareholder20pct3mdishonestydetailqcc: 符合条件股东的CreditCode/StockName JSON列表（供740调用）
 *
 * 【模块6: InvestmentList对外投资（中间变量）】
 *   筛选FundedRatio>20%的记录，去重后存储KeyNo列表：
 *   idishonestflag: 符合条件的被投资企业数（供下游判断）
 *   investee20pct3mdishonestydetailqcc: 符合条件被投资企业的KeyNo JSON列表（供740调用）
 *
 * 状态码: statusCode2003khsfsb
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 将资本金额字符串解析为元double值。
 * 原始值示例："1000万元"、"1000万"、"500元"、"100.5"、"1,000万元"
 * 逻辑：去除逗号→去除非数字/小数点字符→若原始含"万"乘以10000转换为元；若原始含"元"且不含"万"则直接用数值。
 */
private double parseCapitalToYuan(String rawStr) {
    if (rawStr == null || rawStr.trim().isEmpty()) {
        return 0.0;
    }
    String raw = rawStr.trim();
    boolean hasWan = raw.contains("万");
    boolean hasYuan = raw.contains("元");
    // 去除逗号及所有非数字/小数点字符，提取纯数字
    String numStr = raw.replaceAll(",", "").replaceAll("[^0-9.]", "");
    if (numStr.isEmpty()) {
        return 0.0;
    }
    try {
        double val = Double.parseDouble(numStr);
        // 含"万"（不管是否含"元"），转换为元
        if (hasWan) {
            val = val * 10000.0;
        }
        // 若只含"元"不含"万"，认为单位是元，直接返回
        return val ;
    } catch (NumberFormatException e) {
        return 0.0;
    }
}

/**
 * 从List<String>（JSONArray）中取第一个字符串，解析为元double。
 */
private double parseFirstListAmount(JSONArray arr) {
    if (arr == null || arr.isEmpty()) {
        return 0.0;
    }
    String first = arr.getString(0);
    return parseCapitalToYuan(first);
}

/**
 * 解析日期字符串（取前10字符），返回LocalDate；解析失败返回null。
 */
private LocalDate parseDate(String dateStr, DateTimeFormatter fmt) {
    if (dateStr == null || dateStr.trim().isEmpty()) {
        return null;
    }
    try {
        String s = dateStr.trim();
        if (s.length() > 10) {
            s = s.substring(0, 10);
        }
        return LocalDate.parse(s, fmt);
    } catch (Exception e) {
        return null;
    }
}

/**
 * 持股/投资比例字符串解析为double（去除%符号）。
 * 示例："20.5%"、"20.5"、"100%"
 */
private double parsePercent(String percentStr) {
    if (percentStr == null || percentStr.trim().isEmpty()) {
        return 0.0;
    }
    try {
        return Double.parseDouble(percentStr.trim().replace("%", "").trim());
    } catch (NumberFormatException e) {
        return 0.0;
    }
}

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode2003khsfsb", statusCode);

        if (!"200".equals(status)) {
            // 非200：写所有字段默认值后返回
            putAllDefaults(outputMap);
            return outputMap;
        }

        JSONObject resultObj = responseJson.getJSONObject("Result");
        if (resultObj == null) {
            putAllDefaults(outputMap);
            return outputMap;
        }

        int verifyResult = resultObj.getIntValue("VerifyResult");
        if (verifyResult == 0) {
            // VerifyResult=0：无数据，全部写默认值
            putAllDefaults(outputMap);
            return outputMap;
        }

        // VerifyResult=1：有数据，Data是Object
        JSONObject dataObj = resultObj.getJSONObject("Data");
        if (dataObj == null) {
            putAllDefaults(outputMap);
            return outputMap;
        }

        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");
        LocalDate today = LocalDate.now();

        // =========================================================
        // 【模块1: ChangeList变更信息】
        // =========================================================
        int chglegalrepcnt  = 0;   // 法定代表人变更记录数
        int chgequitycnt    = 0;   // 股权变更记录数
        int chgscopecnt     = 0;   // 经营范围变更记录数
        int capdeccnt       = 0;   // 减资记录数
        int capinccnt       = 0;   // 增资记录数
        double capdecratio  = 0.0; // 减资比例（最新一次）
        String latestDecChangeDate = null; // 最新一次减资记录的ChangeDate（用于取最新）

        JSONArray chglegalrepDetail  = new JSONArray();
        JSONArray chgequityDetail    = new JSONArray();
        JSONArray chgscopeDetail     = new JSONArray();
        JSONArray capdecDetail       = new JSONArray();
        JSONArray capincDetail       = new JSONArray();

        JSONArray changeList = dataObj.getJSONArray("ChangeList");
        if (changeList != null) {
            for (int i = 0; i < changeList.size(); i++) {
                JSONObject changeItem = changeList.getJSONObject(i);
                if (changeItem == null) { continue; }

                String changeDate = changeItem.getString("ChangeDate");
                String projectName = changeItem.getString("ProjectName");
                if (changeDate == null || changeDate.trim().isEmpty() || projectName == null) {
                    continue;
                }

                // 过滤：ChangeDate距今<90天
                LocalDate cd = parseDate(changeDate, fmt);
                if (cd == null) { continue; }
                long daysAgo = ChronoUnit.DAYS.between(cd, today);
                if (daysAgo >= 90) { continue; }

                String beforeContent = "";
                String afterContent = "";
                JSONArray beforeList = changeItem.getJSONArray("BeforeList");
                JSONArray afterList  = changeItem.getJSONArray("AfterList");
                if (beforeList != null && !beforeList.isEmpty()) {
                    beforeContent = beforeList.getString(0);
                }
                if (afterList != null && !afterList.isEmpty()) {
                    afterContent = afterList.getString(0);
                }

                // ---- 法定代表人变更 ----
                if (projectName.contains("法定代表")) {
                    chglegalrepcnt++;
                    JSONObject d = new JSONObject();
                    d.put("changedate", changeDate);
                    d.put("projectname", projectName);
                    d.put("beforecontent", beforeContent);
                    d.put("aftercontent", afterContent);
                    chglegalrepDetail.add(d);
                }

                // ---- 股权变更 ----
                boolean isEquity = projectName.contains("投资人") || projectName.contains("股东")
                        || projectName.contains("股权") || projectName.contains("股份转让")
                        || projectName.contains("出资比例") || projectName.contains("出资额")
                        || projectName.contains("出资情况变更");
                if (isEquity) {
                    chgequitycnt++;
                    JSONObject d = new JSONObject();
                    d.put("changedate", changeDate);
                    d.put("projectname", projectName);
                    d.put("beforecontent", beforeContent);
                    d.put("aftercontent", afterContent);
                    chgequityDetail.add(d);
                }

                // ---- 经营范围变更 ----
                boolean isScope = projectName.contains("经营范围") || projectName.contains("主营范围")
                        || projectName.contains("业务范围") || projectName.contains("兼营范围")
                        || projectName.contains("辅营经营范围");
                if (isScope) {
                    chgscopecnt++;
                    JSONObject d = new JSONObject();
                    d.put("changedate", changeDate);
                    d.put("projectname", projectName);
                    d.put("beforecontent", beforeContent);
                    d.put("aftercontent", afterContent);
                    chgscopeDetail.add(d);
                }

                // ---- 注册资本变更（增/减资） ----
                if (projectName.contains("注册资本")) {
                    double beforeAmt = parseFirstListAmount(beforeList);
                    double afterAmt  = parseFirstListAmount(afterList);

                    if (afterAmt < beforeAmt && beforeAmt > 0) {
                        // 减资
                        capdeccnt++;
                        JSONObject d = new JSONObject();
                        d.put("changedate", changeDate);
                        d.put("beforecontent", beforeContent);
                        d.put("aftercontent", afterContent);
                        capdecDetail.add(d);

                        // 取最新一次减资记录计算减资比例（按ChangeDate比较，取最新）
                        if (latestDecChangeDate == null || changeDate.compareTo(latestDecChangeDate) > 0) {
                            latestDecChangeDate = changeDate;
                            double ratio = (beforeAmt - afterAmt) / beforeAmt;
                            capdecratio = new BigDecimal(ratio).setScale(4, RoundingMode.HALF_UP).doubleValue();
                        }
                    } else if (afterAmt > beforeAmt) {
                        // 增资
                        capinccnt++;
                        JSONObject d = new JSONObject();
                        d.put("changedate", changeDate);
                        d.put("beforecontent", beforeContent);
                        d.put("aftercontent", afterContent);
                        capincDetail.add(d);
                    }
                }
            }
        }

        outputMap.put("chglegalrepcnt",  chglegalrepcnt);
        outputMap.put("chglegalrepcntdetail", chglegalrepDetail.toJSONString());
        outputMap.put("chgequitycnt",    chgequitycnt);
        outputMap.put("ent3mequitychangedetailqcc", chgequityDetail.toJSONString());
        outputMap.put("chgscopecnt",     chgscopecnt);
        outputMap.put("chgscopecntdetail", chgscopeDetail.toJSONString());
        outputMap.put("capdecratio",     capdecratio);
        outputMap.put("capdeccnt",       capdeccnt);
        outputMap.put("ent3mregcapdecreasechangedetailqcc", capdecDetail.toJSONString());
        outputMap.put("capinccnt",       capinccnt);
        outputMap.put("ent3mregcapincreasechangedetailqcc", capincDetail.toJSONString());

        // =========================================================
        // 【模块2: Data企业工商信息】
        // =========================================================
        // RegistCapi/RealCapi: 如"1000万元"/"500万元"，去除文字转元double
        String registCapiRaw = dataObj.getString("RegistCapi");
        String realCapiRaw   = dataObj.getString("RealCapi");
        String startDateRaw  = dataObj.getString("StartDate");

        double regcap  = parseCapitalToYuan(registCapiRaw);
        double paidcap = parseCapitalToYuan(realCapiRaw);

        // 实缴比例 = RealCapi / RegistCapi
        double paidcapratio = 0.0;
        if (regcap > 0) {
            paidcapratio = new BigDecimal(paidcap / regcap)
                    .setScale(4, RoundingMode.HALF_UP).doubleValue();
        }

        // 成立日期：C_D_ DATE类型，平台 ConvertFieldTypeStep.parseValue2Date() 仅支持
        // "yyyy-MM-dd HH:mm:ss" 和 "yyyy-MM-dd'T'HH:mm:ss" 两种格式，
        // 纯 "yyyy-MM-dd" 无时间分量会导致 DateUtils.parseDate() 抛 ParseException。
        // 修复：取前10字符后拼接 " 00:00:00"，使格式符合平台要求。
        String estabdate = null;
        if (startDateRaw != null && !startDateRaw.trim().isEmpty()) {
            String datePart = startDateRaw.trim().length() > 10
                    ? startDateRaw.trim().substring(0, 10)
                    : startDateRaw.trim();
            estabdate = datePart + " 00:00:00"; // 补全时间分量，满足 yyyy-MM-dd HH:mm:ss 要求
        }

        outputMap.put("regcap",       regcap);
        outputMap.put("paidcap",      paidcap);
        outputMap.put("paidcapratio", paidcapratio);
        outputMap.put("estabdate",    estabdate);

        // =========================================================
        // 【模块3: RevokeInfo注销吊销信息】
        // =========================================================
        // RevokeInfo是Data内的Object（非数组），检查CancelDate或RevokeDate距今<90天
        int revokecnt = 0;
        JSONArray revokecntdetailArr = new JSONArray();

        JSONObject revokeInfo = dataObj.getJSONObject("RevokeInfo");
        if (revokeInfo != null) {
            String cancelDate = revokeInfo.getString("CancelDate");
            String revokeDate = revokeInfo.getString("RevokeDate");
            String cancelReason = revokeInfo.getString("CancelReason");
            String revokeReason = revokeInfo.getString("RevokeReason");

            boolean cancelRecent = false;
            boolean revokeRecent = false;

            if (cancelDate != null && !cancelDate.trim().isEmpty()) {
                LocalDate cd2 = parseDate(cancelDate, fmt);
                if (cd2 != null && ChronoUnit.DAYS.between(cd2, today) < 90) {
                    cancelRecent = true;
                }
            }
            if (revokeDate != null && !revokeDate.trim().isEmpty()) {
                LocalDate rd = parseDate(revokeDate, fmt);
                if (rd != null && ChronoUnit.DAYS.between(rd, today) < 90) {
                    revokeRecent = true;
                }
            }

            // 只要CancelDate或RevokeDate其中一个距今<90天，则计入1条记录
            if (cancelRecent || revokeRecent) {
                revokecnt = 1;
                JSONObject d = new JSONObject();
                if (cancelDate != null)  { d.put("canceldate",   cancelDate); }
                if (revokeDate != null)  { d.put("revokedate",   revokeDate); }
                if (cancelReason != null) { d.put("cancelreason", cancelReason); }
                if (revokeReason != null) { d.put("revokereason", revokeReason); }
                revokecntdetailArr.add(d);
            }
        }

        outputMap.put("revokecnt",       revokecnt);
        outputMap.put("revokecntdetail", revokecntdetailArr.toJSONString());

        // 关联企业近3个月注销吊销：本接口无关联企业数据，固定输出0/空
        outputMap.put("relatedent3mcancelrevokecountqcc",          0);
        outputMap.put("relatedent3mcancelrevokecountdetailqcc",    new JSONArray().toJSONString());

        // =========================================================
        // 【模块4: TaxCreditList纳税信用等级】
        // =========================================================
        // 取Year字段最大（最新年度）的那条记录的Level值
        String taxcreditgrade = null;
        JSONArray taxCreditList = dataObj.getJSONArray("TaxCreditList");
        if (taxCreditList != null && !taxCreditList.isEmpty()) {
            String maxYear = null;
            for (int i = 0; i < taxCreditList.size(); i++) {
                JSONObject tcItem = taxCreditList.getJSONObject(i);
                if (tcItem == null) { continue; }
                String year  = tcItem.getString("Year");
                String level = tcItem.getString("Level");
                if (year == null || year.trim().isEmpty()) { continue; }
                if (maxYear == null || year.compareTo(maxYear) > 0) {
                    maxYear = year;
                    taxcreditgrade = level;
                }
            }
        }
        outputMap.put("taxcreditgrade", taxcreditgrade);

        // =========================================================
        // 【模块5: PubPartnerList最新公示股东信息（中间变量）】
        // =========================================================
        // 筛选StockPercent>20%的记录，去重后存储CreditCode（或StockName）作为后续740调用的标识
        // 注：PubPartnerList中无KeyNo字段，使用CreditCode作为企业标识
        Set<String> partnerKeySet = new HashSet<>();
        Set<String> partnerNameSet = new LinkedHashSet<>(); // 股东名称列表（保序去重）
        JSONArray partnerKeyArray = new JSONArray(); // 供下游740调用

        JSONArray pubPartnerList = dataObj.getJSONArray("PubPartnerList");
        if (pubPartnerList != null) {
            for (int i = 0; i < pubPartnerList.size(); i++) {
                JSONObject partnerItem = pubPartnerList.getJSONObject(i);
                if (partnerItem == null) { continue; }
                String stockPercentStr = partnerItem.getString("StockPercent");
                double stockPercent = parsePercent(stockPercentStr);
                if (stockPercent <= 20.0) { continue; }

                // 以CreditCode去重；若CreditCode为空则以StockName去重
                String creditCode = partnerItem.getString("CreditCode");
                String stockName  = partnerItem.getString("StockName");
                String key = (creditCode != null && !creditCode.trim().isEmpty())
                        ? creditCode.trim() : (stockName != null ? stockName.trim() : "");
                if (key.isEmpty() || partnerKeySet.contains(key)) { continue; }
                partnerKeySet.add(key);
                if (stockName != null && !stockName.trim().isEmpty()) {
                    partnerNameSet.add(stockName.trim());
                }

                JSONObject keyItem = new JSONObject();
                keyItem.put("creditcode",   creditCode != null ? creditCode : "");
                keyItem.put("stockname",    stockName  != null ? stockName  : "");
                keyItem.put("stockpercent", stockPercentStr != null ? stockPercentStr : "");
                partnerKeyArray.add(keyItem);
            }
        }

        // pdishonestflag: 符合条件的股东列表长度（实际失信数由下游740决定，此处输出候选数作为中间变量）
        outputMap.put("pdishonestflag",                     partnerKeyArray.size());
        outputMap.put("shareholder20pct3mdishonestydetailqcc", partnerKeyArray.toJSONString());
        // 独立股东名称列表（供下游循环调用740）
        JSONArray partnerCreditCodeList = new JSONArray();
        partnerCreditCodeList.addAll(partnerNameSet);
        outputMap.put("shareholder20pctcreditcodelist", partnerCreditCodeList.toJSONString());

        // =========================================================
        // 【模块6: InvestmentList对外投资（中间变量）】
        // =========================================================
        // 筛选FundedRatio>20%的记录，去重KeyNo列表
        Set<String> investeeKeySet = new HashSet<>();
        Set<String> investeeNameSet = new LinkedHashSet<>(); // 公司名称列表（保序去重）
        JSONArray investeeKeyArray = new JSONArray(); // 供下游740调用

        JSONArray investmentList = dataObj.getJSONArray("InvestmentList");
        if (investmentList != null) {
            for (int i = 0; i < investmentList.size(); i++) {
                JSONObject invItem = investmentList.getJSONObject(i);
                if (invItem == null) { continue; }
                String fundedRatioStr = invItem.getString("FundedRatio");
                double fundedRatio = parsePercent(fundedRatioStr);
                if (fundedRatio <= 20.0) { continue; }

                String keyNo = invItem.getString("KeyNo");
                String name  = invItem.getString("Name");
                String key = (keyNo != null && !keyNo.trim().isEmpty()) ? keyNo.trim() : "";
                if (key.isEmpty() || investeeKeySet.contains(key)) { continue; }
                investeeKeySet.add(key);
                if (name != null && !name.trim().isEmpty()) {
                    investeeNameSet.add(name.trim());
                }

                JSONObject keyItem = new JSONObject();
                keyItem.put("keyno",       keyNo != null ? keyNo : "");
                keyItem.put("name",        name  != null ? name  : "");
                keyItem.put("fundedratio", fundedRatioStr != null ? fundedRatioStr : "");
                investeeKeyArray.add(keyItem);
            }
        }

        // idishonestflag: 符合条件的被投资企业列表长度（实际失信数由下游740决定）
        outputMap.put("idishonestflag",                     investeeKeyArray.size());
        outputMap.put("investee20pct3mdishonestydetailqcc", investeeKeyArray.toJSONString());
        // 独立公司名称列表（供下游循环调用740）
        JSONArray investeeKeyNoList = new JSONArray();
        investeeKeyNoList.addAll(investeeNameSet);
        outputMap.put("investee20pctkeynolist", investeeKeyNoList.toJSONString());

    } catch (Exception e) {
        log.error("[ICustomEtlHandlerAfterCaller-after execution exception]sequenceId:{},className:{},context:{}", context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

/**
