/**
 * 887裁判文书核查后置ETL（分页，PAGE）。
 * 企查查按PublishDate倒序返回，earlyStop=true：遇超90天记录即flag=false终止翻页。
 *
 * 过滤条件及累计规则：
 *   1. loandisputecnt（被告借款纠纷案件数）：
 *      PublishDate距今<90天 且 CaseReason包含借款相关关键词
 *      且 PartyList中RoleType包含"被"且Name==searchKey
 *      → loandisputecnt++，累计defendamt（Amount字段）
 *
 *   2. ent3mselfprosecutioncountqcc（原告案件数）：
 *      PublishDate距今<90天 且 PartyList中RoleType包含"原"且Name==searchKey
 *      → ent3mselfprosecutioncountqcc++，取单笔最大ent3mselfprosecutionsingleamountqcc（Amount字段）
 *
 *   3. preservcnt（被保全记录数）：
 *      PublishDate距今<90天 且 CaseType=="bq"（非诉保全审查案件）
 *      且 PartyList中RoleType包含"被"且Name==searchKey
 *      → preservcnt++
 *
 * 跨页状态：使用etlHandlerContext.getBussMap()保存：
 *   accLoanCnt, accLoanDetail, accSelfCnt, accSelfDetail,
 *   accSelfAmt, accPreservCnt, accPreservDetail, accDefendAmt
 *
 * 输出字段（serviceParam）：
 *   loandisputecnt                              DOUBLE  被告借款纠纷案件数
 *   ent3mjudgmentloandisputedefendantdetailqcc  STRING  被告借款纠纷详情
 *   ent3mselfprosecutioncountqcc                DOUBLE  原告案件数
 *   ent3mselfprosecutioncountdetailqcc          STRING  原告案件详情
 *   ent3mselfprosecutionsingleamountqcc         DOUBLE  原告案件单笔最高涉案金额
 *   preservcnt                                  DOUBLE  被保全记录数
 *   preservcntdetail                            STRING  被保全记录详情
 *   defendamt                                   DOUBLE  被告涉案金额累计
 *   statusCode887cpwshc                         DOUBLE  状态码
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出，供规则判断接口是否正常返回
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode887cpwshc", statusCode);

        // flag默认true（激进策略：默认继续翻页，在终止条件下置false）
        boolean flag = true;

        // 上下文对象延迟声明为null（防御性：status非200时无需获取）
        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map<String, String> allParam = null;       // allParam：含所有入参展开值，key=DS字段名（如C_S_PAGEINDEX）
        Map<String, String> requestInParam = null; // requestInParam：可写入下一页入参，平台在下次调用时读取

        if ("200".equals(status)) {

            //===== 上下文获取：独立try-catch，获取失败则停止翻页 =====
            // 修复：先获取requestInParam，再null-safe获取etlRequestResult
            try {
                etlHandlerContext = context.getEtlHandlerContext();
                requestInParam = etlHandlerContext.getRequestInParam();  // 先获取，MOCK模式下也可用
                EtlRequestResult tempResult = etlHandlerContext.getEtlRequestResult();
                if (tempResult != null) {  // MOCK模式下etlRequestResult为null，正常
                    etlRequestResult = tempResult;
                    allParam = etlRequestResult.getAllParam();
                }
            } catch (Exception e) {
                flag = false; // 真正的上下文获取失败才终止翻页
                e.printStackTrace();
            }

            //===== 业务处理 =====
            JSONObject resultObj = responseJson.getJSONObject("Result");
            if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                // VerifyResult=0：无数据，显式置flag=false
                flag = false;
                outputMap.put("loandisputecnt", 0);
                outputMap.put("ent3mjudgmentloandisputedefendantdetailqcc", new JSONArray().toJSONString());
                outputMap.put("ent3mselfprosecutioncountqcc", 0);
                outputMap.put("ent3mselfprosecutioncountdetailqcc", new JSONArray().toJSONString());
                outputMap.put("ent3mselfprosecutionsingleamountqcc", 0.0);
                outputMap.put("preservcnt", 0);
                outputMap.put("preservcntdetail", new JSONArray().toJSONString());
                outputMap.put("defendamt", 0.0);
            } else {
                // 获取searchKey：优先从requestInParam读取（MOCK和非MOCK模式均可用）
                String searchKey = (requestInParam != null) ? (String) requestInParam.get("C_S_QCCSEARCHKEY") : "";
                if (searchKey == null) { searchKey = ""; }

                LocalDate today = LocalDate.now();
                DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                // 累计变量在bussMap try-catch外声明（保证bussMap异常时仍有输出）
                int accLoanCnt = 0;
                JSONArray accLoanDetail = new JSONArray();
                int accSelfCnt = 0;
                JSONArray accSelfDetail = new JSONArray();
                double maxSelfAmt = 0.0;
                int accPreservCnt = 0;
                JSONArray accPreservDetail = new JSONArray();
                double accDefendAmt = 0.0;

                //===== bussMap跨页状态操作：独立try-catch =====
                try {
                    // bussMap：平台原生跨页状态容器，同一请求多次after()间共享，平台管理生命周期
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    // 恢复上一页写入的累计状态（首页时bussMap为空，使用上方声明的初始值）
                    if (bussMap.containsKey("accLoanCnt")) { accLoanCnt = ((Number) bussMap.get("accLoanCnt")).intValue(); }
                    if (bussMap.containsKey("accLoanDetail")) { accLoanDetail = JSON.parseArray(bussMap.get("accLoanDetail").toString()); }
                    if (bussMap.containsKey("accSelfCnt")) { accSelfCnt = ((Number) bussMap.get("accSelfCnt")).intValue(); }
                    if (bussMap.containsKey("accSelfDetail")) { accSelfDetail = JSON.parseArray(bussMap.get("accSelfDetail").toString()); }
                    if (bussMap.containsKey("accSelfAmt")) { maxSelfAmt = ((Number) bussMap.get("accSelfAmt")).doubleValue(); }
                    if (bussMap.containsKey("accPreservCnt")) { accPreservCnt = ((Number) bussMap.get("accPreservCnt")).intValue(); }
                    if (bussMap.containsKey("accPreservDetail")) { accPreservDetail = JSON.parseArray(bussMap.get("accPreservDetail").toString()); }
                    if (bussMap.containsKey("accDefendAmt")) { accDefendAmt = ((Number) bussMap.get("accDefendAmt")).doubleValue(); }

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);

                            // 读取PublishDate，取前10字符（yyyy-MM-dd），兼容"yyyy-MM-dd HH:mm:ss"格式
                            String publishDateStr = item.getString("PublishDate");
                            if (publishDateStr == null || publishDateStr.isEmpty()) {
                                continue; // 无日期记录跳过
                            }
                            if (publishDateStr.length() > 10) {
                                publishDateStr = publishDateStr.substring(0, 10);
                            }
                            LocalDate publishDate = LocalDate.parse(publishDateStr, fmt);
                            long daysAgo = ChronoUnit.DAYS.between(publishDate, today);

                            // earlyStop：企查查按倒序返回，遇超90天记录则后续均超，flag=false并终止循环
                            if (daysAgo >= 90) {
                                flag = false;
                                break;
                            }

                            String caseReason = item.getString("CaseReason");
                            String caseType   = item.getString("CaseType");
                            String amountStr  = item.getString("Amount");
                            double amount = parseAmount(amountStr);

                            boolean isDefendant  = "true".equalsIgnoreCase(item.getString("IsDefendant"));
                            boolean isProsecutor = "true".equalsIgnoreCase(item.getString("IsProsecutor"));
                            boolean isLoanDispute = containsLoanKeyword(caseReason);
                            boolean isPreserv     = isPreservCase(caseType, caseReason);

                            // ===== 被告借款纠纷 + 被告涉案金额 =====
                            if (isDefendant && isLoanDispute) {
                                accLoanCnt++;
                                accDefendAmt += amount;
                                JSONObject detailItem = new JSONObject();
                                String v1 = item.getString("CaseName"); if (v1 != null) { detailItem.put("casename", v1); }
                                String v2 = item.getString("CaseReason"); if (v2 != null) { detailItem.put("casereason", v2); }
                                String v3 = item.getString("CaseNo"); if (v3 != null) { detailItem.put("caseno", v3); }
                                if (amountStr != null) { detailItem.put("amount", amountStr); }
                                String v4 = item.getString("IsDefendant"); if (v4 != null) { detailItem.put("isdefendant", v4); }
                                String v5 = item.getString("PublishDate"); if (v5 != null) { detailItem.put("publishdate", v5); }
                                accLoanDetail.add(detailItem);
                            }

                            // ===== 被保全记录 =====
                            if (isDefendant && isPreserv) {
                                accPreservCnt++;
                                JSONObject preservItem = new JSONObject();
                                String p1 = item.getString("CaseName"); if (p1 != null) { preservItem.put("casename", p1); }
                                String p2 = item.getString("CaseReason"); if (p2 != null) { preservItem.put("casereason", p2); }
                                String p3 = item.getString("CaseNo"); if (p3 != null) { preservItem.put("caseno", p3); }
                                if (amountStr != null) { preservItem.put("amount", amountStr); }
                                String p4 = item.getString("CaseType"); if (p4 != null) { preservItem.put("category", p4); }
                                String p5 = item.getString("PublishDate"); if (p5 != null) { preservItem.put("publishdate", p5); }
                                accPreservDetail.add(preservItem);
                            }

                            // ===== 原告案件笔数及金额 =====
                            if (isProsecutor) {
                                accSelfCnt++;
                                maxSelfAmt = Math.max(maxSelfAmt, amount);
                                JSONObject selfItem = new JSONObject();
                                String s1 = item.getString("CaseName"); if (s1 != null) { selfItem.put("casename", s1); }
                                String s2 = item.getString("CaseReason"); if (s2 != null) { selfItem.put("casereason", s2); }
                                String s3 = item.getString("CaseNo"); if (s3 != null) { selfItem.put("caseno", s3); }
                                if (amountStr != null) { selfItem.put("amount", amountStr); }
                                String s4 = item.getString("IsProsecutor"); if (s4 != null) { selfItem.put("isprosecutor", s4); }
                                String s5 = item.getString("PublishDate"); if (s5 != null) { selfItem.put("publishdate", s5); }
                                accSelfDetail.add(selfItem);
                            }
                        }
                    }

                    // 写回跨页状态（平台管理生命周期，无需手动清理）
                    bussMap.put("accLoanCnt", accLoanCnt);
                    bussMap.put("accLoanDetail", accLoanDetail.toJSONString());
                    bussMap.put("accSelfCnt", accSelfCnt);
                    bussMap.put("accSelfDetail", accSelfDetail.toJSONString());
                    bussMap.put("accSelfAmt", maxSelfAmt);
                    bussMap.put("accPreservCnt", accPreservCnt);
                    bussMap.put("accPreservDetail", accPreservDetail.toJSONString());
                    bussMap.put("accDefendAmt", accDefendAmt);
                    etlHandlerContext.setBussMap(bussMap);
                    context.setEtlHandlerContext(etlHandlerContext); // 仅在setBussMap后调用一次

                } catch (Exception e) {
                    flag = false; // bussMap操作异常，停止翻页
                    e.printStackTrace();
                }

                // 输出在bussMap try-catch外（保证bussMap失败时仍有默认输出）
                outputMap.put("loandisputecnt", accLoanCnt);
                outputMap.put("ent3mjudgmentloandisputedefendantdetailqcc", accLoanDetail.toJSONString());
                outputMap.put("ent3mselfprosecutioncountqcc", accSelfCnt);
                outputMap.put("ent3mselfprosecutioncountdetailqcc", accSelfDetail.toJSONString());
                outputMap.put("ent3mselfprosecutionsingleamountqcc", maxSelfAmt);
                outputMap.put("preservcnt", accPreservCnt);
                outputMap.put("preservcntdetail", accPreservDetail.toJSONString());
                outputMap.put("defendamt", accDefendAmt);

                //===== 分页控制：在业务处理之后、独立try-catch =====
                try {
                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("887cpwshchz-after:sequenceId:{},from={},size={},total={}",
                                    context.getSequenceId(), currentFrom, size, total);
                            // ceil(total/size)：2参数divide + setScale（与参考实现一致）
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX",
                                        String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                // setRequestInParam后不再调用context.setEtlHandlerContext（已在setBussMap时调用）
                                flag = true;
                                log.info("887cpwshchz-after:sequenceId:{},context={}",
                                        context.getSequenceId(), JSON.toJSONString(context));
                            } else {
                                flag = false; // 已是最后一页
                            }
                        } else {
                            flag = false; // Paging节点缺失
                        }
                    }
                } catch (Exception e) {
                    flag = false; // 分页计算异常，停止翻页
                    e.printStackTrace();
                }
            }
        } else {
            // 非200状态，终止翻页
            flag = false;
            outputMap.put("loandisputecnt", 0);
            outputMap.put("ent3mjudgmentloandisputedefendantdetailqcc", new JSONArray().toJSONString());
            outputMap.put("ent3mselfprosecutioncountqcc", 0);
            outputMap.put("ent3mselfprosecutioncountdetailqcc", new JSONArray().toJSONString());
            outputMap.put("ent3mselfprosecutionsingleamountqcc", 0.0);
            outputMap.put("preservcnt", 0);
            outputMap.put("preservcntdetail", new JSONArray().toJSONString());
            outputMap.put("defendamt", 0.0);
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[887cpwshchz-after]sequenceId:{},context:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

/**
 * 判断案由是否包含借款合同纠纷相关关键词
 * 参考882法院公告核查及888开庭公告核查的关键词列表
 */
private boolean containsLoanKeyword(String caseReason) {
    if (caseReason == null || caseReason.isEmpty()) { return false; }
    return caseReason.contains("借款合同") || caseReason.contains("民间借贷")
        || caseReason.contains("金融借款合同") || caseReason.contains("票据")
        || caseReason.contains("借贷") || caseReason.contains("拆借")
        || caseReason.contains("融资租赁") || caseReason.contains("借款");
}

/**
 * 判断是否为被保全案件（CaseType=="bq"或CaseReason包含"保全"或"非诉"）
 */
private boolean isPreservCase(String caseType, String caseReason) {
    if ("bq".equals(caseType)) { return true; }
    if (caseType != null && caseType.contains("保全")) { return true; }
    if (caseReason != null && (caseReason.contains("保全") || caseReason.contains("非诉"))) { return true; }
    return false;
}

/**
 * 解析金额字符串，去除非数字字符（保留小数点），返回double值。
 * 无法解析时返回0.0。
 */
private double parseAmount(String amountStr) {
    if (amountStr == null || amountStr.isEmpty()) { return 0.0; }
    // 去除除数字和小数点之外的所有字符（如"元"、","、空格等）
    String cleaned = amountStr.replaceAll("[^0-9.]", "");
    if (cleaned.isEmpty()) { return 0.0; }
    try {
        return Double.parseDouble(cleaned);
    } catch (NumberFormatException e) {
        return 0.0;
    }
}

