/**
 * 761破产重整核查后置ETL（分页，PAGE）。
 * ETL逻辑：直接读取第一页Paging.TotalRecords作为破产重整记录总数，不做逐条过滤。
 * 仅在第一页读取TotalRecords并写入输出，后续页flag=false不继续翻页。
 * 输出字段:
 *   bankruptflag: Paging.TotalRecords破产重整记录总数
 *   bankruptflagdetail: 第一页Data中每条记录的明细JSONArray（caseno,publicdate）
 *   statusCode761pcczhc: 接口HTTP状态码
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
