import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.Map;

/**
 * 748严重违法核查后置ETL（普通，非分页）。
 * 接口地址: https://api.qichacha.com/SeriousIllegalCheck/GetList
 * 接口响应: {"Status":"200","Result":{"VerifyResult":1,"Data":[{...}]}}
 * Data字段: AddReason(列入原因), AddDate(列入日期), AddOffice(列入机关), RemoveReason(移出原因), RemoveDate(移出日期)
 * ETL逻辑: 遍历Data数组，过滤RemoveDate为null或空字符串的记录（即当前仍在列的严重违法记录），计数并构建详情。
 * 输出字段:
 *   seriousviolflag: 当前仍在列的严重违法记录数量（RemoveDate为空的记录总数）
 *   seriousviolflagdetail: 严重违法记录详情JSONArray[{addreason,adddate,addoffice,removereason,removedate}]
 *   statusCode748yzwfhc: 接口HTTP状态码，200=成功
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出，供规则判断接口是否正常返回；非200时也要写0避免NPE
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode748yzwfhc", statusCode);

        if (!"200".equals(status)) {
            // 非200状态：不处理业务逻辑，写默认值
            outputMap.put("seriousviolflag", 0);
            outputMap.put("seriousviolflagdetail", new JSONArray().toJSONString());
            return outputMap;
        }

        JSONObject resultObj = responseJson.getJSONObject("Result");
        if (resultObj == null) {
            outputMap.put("seriousviolflag", 0);
            outputMap.put("seriousviolflagdetail", new JSONArray().toJSONString());
            return outputMap;
        }

        int verifyResult = resultObj.getIntValue("VerifyResult");
        if (verifyResult == 0) {
            // VerifyResult=0：无严重违法记录，返回0
            outputMap.put("seriousviolflag", 0);
            outputMap.put("seriousviolflagdetail", new JSONArray().toJSONString());
            return outputMap;
        }

        // VerifyResult=1：存在记录，遍历Data数组过滤RemoveDate为空的记录
        JSONArray dataArray = resultObj.getJSONArray("Data");
        int seriousviolflag = 0;
        JSONArray detailArray = new JSONArray();

        if (dataArray != null) {
            for (int i = 0; i < dataArray.size(); i++) {
                JSONObject item = dataArray.getJSONObject(i);

                // 过滤：RemoveDate为null或空字符串表示当前仍在严重违法列表中
                String removeDate = (String) item.get("RemoveDate");
                if (removeDate != null && !removeDate.isEmpty()) {
                    continue; // 已移出，跳过
                }

                // RemoveDate为空，计入当前有效的严重违法记录
                seriousviolflag++;

                JSONObject detailItem = new JSONObject();
                String addReason = (String) item.get("AddReason");
                String addDate = (String) item.get("AddDate");
                String addOffice = (String) item.get("AddOffice");
                String removeReason = (String) item.get("RemoveReason");
                String removeDateVal = (String) item.get("RemoveDate");
                if (addReason != null) { detailItem.put("addreason", addReason); }         // 列入原因
                if (addDate != null) { detailItem.put("adddate", addDate); }               // 列入日期
                if (addOffice != null) { detailItem.put("addoffice", addOffice); }         // 列入机关
                if (removeReason != null) { detailItem.put("removereason", removeReason); } // 移出原因
                if (removeDateVal != null) { detailItem.put("removedate", removeDateVal); } // 移出日期（此处为空）
                detailArray.add(detailItem);
            }
        }

        outputMap.put("seriousviolflag", seriousviolflag);
        outputMap.put("seriousviolflagdetail", detailArray.toJSONString());

    } catch (Exception e) {
        log.error("[ICustomEtlHandlerAfterCaller-after execution exception]sequenceId:{},className:{},context:{}", context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

