import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import cn.hutool.core.util.XmlUtil;
import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import javax.xml.xpath.XPathConstants;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;

/**
 * 企业征信报告后置ETL (HTTP-POST, comSingleCacheQuery, T00221001, reportModelType=1)
 *
 * 处理原则:
 *   1. 仅校验 retCode=1，不校验 consistent。
 *   2. 按新增企业数据库设计 Excel 的索引映射解析 reportModelType=1 XML。
 *   3. 严格按原模块描述计算，不额外增加逾期本金、BusinessType 总计行、旧字段兜底等扩展口径。
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

private static double safeDouble(Object val) {
    if (val == null) return 0.0;
    String s = val.toString().trim();
    if (s.isEmpty() || "--".equals(s) || "None".equalsIgnoreCase(s) || "null".equalsIgnoreCase(s)) return 0.0;
    s = s.replace(",", "");
    try {
        return Double.parseDouble(s);
    } catch (Exception e) {
        return 0.0;
    }
}

private static int safeInt(Object val) {
    return (int) safeDouble(val);
}

private static String elemText(Element el, String tagName) {
    if (el == null) return "";
    NodeList nl = el.getElementsByTagName(tagName);
    if (nl == null || nl.getLength() == 0) return "";
    Node n = nl.item(0);
    if (n == null) return "";
    String t = n.getTextContent();
    return t == null ? "" : t.trim();
}

private static NodeList nodeSet(Document doc, String xpath) {
    try {
        return (NodeList) XmlUtil.getByXPath(xpath, doc, XPathConstants.NODESET);
    } catch (Exception e) {
        return null;
    }
}

private static String xpathText(Document doc, String xpath) {
    try {
        Object v = XmlUtil.getByXPath(xpath, doc, XPathConstants.STRING);
        return v == null ? "" : v.toString().trim();
    } catch (Exception e) {
        return "";
    }
}

private static boolean isUnsettled(String status) {
    return "1".equals(status);
}

private static boolean isBadAsset(String assetQuality) {
    return "3".equals(assetQuality);
}

private static boolean isConcernAsset(String assetQuality) {
    return "2".equals(assetQuality);
}

private static String toJsonArray(List list) {
    if (list == null || list.isEmpty()) return "[]";
    return JSON.toJSONString(list, SerializerFeature.DisableCircularReferenceDetect);
}

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> out = Maps.newHashMap();
    out.put("odloanacctcnt",       0);
    out.put("odloanacctcntdetail", "[]");
    out.put("badloanbal",          0.0);
    out.put("attnloanacctcnt",     0);
    out.put("odguaacctcnt",        0);
    out.put("odguaacctcntdetail",  "[]");
    out.put("badguabal",           0.0);
    out.put("attnguaacctcnt",      0);
    out.put("unpaidintbal",        0.0);
    out.put("qyzxbgstatuscode",    0);
    out.put("qyzxbgreportid",      "");

    try {
        if (response == null || response.trim().isEmpty()) {
            log.warn("qyzxbghz: empty response, sequenceId={}", context.getSequenceId());
            return out;
        }

        Document soapDoc = XmlUtil.parseXml(response);
        out.put("qyzxbgreportid", xpathText(soapDoc, "//return/reportId/text()"));

        int retCode = safeInt(xpathText(soapDoc, "//return/retCode/text()"));
        out.put("qyzxbgstatuscode", retCode);
        if (retCode != 1) {
            log.warn("qyzxbghz: retCode not success, retCode={}, retInfo={}, sequenceId={}",
                retCode, xpathText(soapDoc, "//return/retInfo/text()"), context.getSequenceId());
            return out;
        }

        String innerXml = xpathText(soapDoc, "//return/result/text()");
        if (innerXml == null || innerXml.trim().isEmpty()) {
            log.warn("qyzxbghz: result is empty, sequenceId={}", context.getSequenceId());
            return out;
        }

        innerXml = innerXml.trim();
        if (innerXml.startsWith("&lt;")) {
            innerXml = innerXml.replace("&lt;", "<").replace("&gt;", ">").replace("&amp;", "&");
        }
        String cdataStart = "<" + "!" + "[CDATA[";
        String cdataEnd = "]" + "]" + ">";
        if (innerXml.startsWith(cdataStart)) {
            innerXml = innerXml.substring(cdataStart.length());
        }
        if (innerXml.endsWith(cdataEnd)) {
            innerXml = innerXml.substring(0, innerXml.length() - cdataEnd.length());
        }

        Document innerDoc = XmlUtil.parseXml(innerXml);
        String innerReportId = xpathText(innerDoc, "//Crt2_C_ReportHeader/reportid/text()");
        if ((out.get("qyzxbgreportid") == null || out.get("qyzxbgreportid").toString().isEmpty()) && !innerReportId.isEmpty()) {
            out.put("qyzxbgreportid", innerReportId);
        }

        // 模块1: ED01A JOIN ED01B ON ED01AI01；账户数去重计数，详情保留全部符合条件的 ED01B 明细。
        NodeList basicNodes = nodeSet(innerDoc, "//basicBorrowingList/Crt2_C_BasicBorrowing");
        Set unsettledLoanAccts = new HashSet();
        if (basicNodes != null) {
            for (int i = 0; i < basicNodes.getLength(); i++) {
                Element basic = (Element) basicNodes.item(i);
                String acct = elemText(basic, "loanaccountid");
                if (!acct.isEmpty() && isUnsettled(elemText(basic, "accountactivitystatus"))) {
                    unsettledLoanAccts.add(acct);
                }
            }
        }

        NodeList loanNodes = nodeSet(innerDoc, "//loanRepaymentList/Crt2_C_LoanRepayment");
        Set odLoanAcctSet = new HashSet();
        List odLoanDetails = new ArrayList();
        if (loanNodes != null) {
            for (int i = 0; i < loanNodes.getLength(); i++) {
                Element loan = (Element) loanNodes.item(i);
                String acct = elemText(loan, "loanaccount");
                if (acct.isEmpty() || !unsettledLoanAccts.contains(acct)) continue;

                double totalOverdue = safeDouble(elemText(loan, "totaloverdue"));
                int overdueMonths = safeInt(elemText(loan, "overduemonths"));
                if (totalOverdue > 0 || overdueMonths > 0) {
                    odLoanAcctSet.add(acct);
                    Map item = new LinkedHashMap();
                    item.put("loanaccount", acct);
                    item.put("totaloverdue", totalOverdue);
                    item.put("overduemonths", overdueMonths);
                    odLoanDetails.add(item);
                }
            }
        }
        out.put("odloanacctcnt", odLoanAcctSet.size());
        out.put("odloanacctcntdetail", toJsonArray(odLoanDetails));

        // 模块2: EB02AH。仅按资产质量分类聚合，不对 BusinessType 做特殊处理。
        NodeList othLoanNodes = nodeSet(innerDoc, "//summaryOfLoans/othLoanSumList/Crt2_C_OthLoanSum");
        double badLoanBal = 0.0;
        int attnLoanAcctCnt = 0;
        if (othLoanNodes != null) {
            for (int i = 0; i < othLoanNodes.getLength(); i++) {
                Element item = (Element) othLoanNodes.item(i);
                String assetQuality = elemText(item, "assetquality");
                if (isBadAsset(assetQuality)) {
                    badLoanBal += safeDouble(elemText(item, "balance"));
                }
                if (isConcernAsset(assetQuality)) {
                    attnLoanAcctCnt += safeInt(elemText(item, "accountnumber"));
                }
            }
        }
        out.put("badloanbal", badLoanBal);
        out.put("attnloanacctcnt", attnLoanAcctCnt);

        // 模块3: ED07 条件记录数 + ED08 条件记录数；异常/空值按不符合处理。
        int odGuaAcctCnt = 0;
        List odGuaDetails = new ArrayList();

        NodeList rrAccountNodes = nodeSet(innerDoc, "//relatedRepayment/rrAccountList/Crt2_C_RRAccount");
        if (rrAccountNodes != null) {
            for (int i = 0; i < rrAccountNodes.getLength(); i++) {
                Element rr = (Element) rrAccountNodes.item(i);
                double totalOverdue = safeDouble(elemText(rr, "totaloverdue"));
                int overdueMonths = safeInt(elemText(rr, "overduemonths"));
                int repaymentState = safeInt(elemText(rr, "repaymentstate"));
                if (totalOverdue > 0 || overdueMonths > 0 || repaymentState > 0) {
                    odGuaAcctCnt++;
                    Map item = new LinkedHashMap();
                    item.put("accountid", elemText(rr, "accountid"));
                    item.put("totaloverdue", totalOverdue);
                    item.put("overduemonths", overdueMonths);
                    item.put("repaymentstate", repaymentState);
                    odGuaDetails.add(item);
                }
            }
        }

        NodeList rrDiscountNodes = nodeSet(innerDoc, "//relatedRepayment/rrDiscountingList/Crt2_C_RRDiscounting");
        if (rrDiscountNodes != null) {
            for (int i = 0; i < rrDiscountNodes.getLength(); i++) {
                Element rr = (Element) rrDiscountNodes.item(i);
                double totalOverdue = safeDouble(elemText(rr, "totaloverdue"));
                if (totalOverdue > 0) {
                    odGuaAcctCnt++;
                    Map item = new LinkedHashMap();
                    item.put("discountaccountid", elemText(rr, "discountaccountid"));
                    item.put("totaloverdue", totalOverdue);
                    odGuaDetails.add(item);
                }
            }
        }
        out.put("odguaacctcnt", odGuaAcctCnt);
        out.put("odguaacctcntdetail", toJsonArray(odGuaDetails));

        // 模块4: EB03A。仅按资产质量分类聚合，不对 BusinessType 做特殊处理。
        NodeList unscGuaNodes = nodeSet(innerDoc, "//guaranteeSummary/unscGuaranteeList/Crt2_C_UnscGuarantee");
        double badGuaBal = 0.0;
        int attnGuaAcctCnt = 0;
        if (unscGuaNodes != null) {
            for (int i = 0; i < unscGuaNodes.getLength(); i++) {
                Element item = (Element) unscGuaNodes.item(i);
                String assetQuality = elemText(item, "assetquality");
                if (isBadAsset(assetQuality)) {
                    badGuaBal += safeDouble(elemText(item, "balance"));
                }
                if (isConcernAsset(assetQuality)) {
                    attnGuaAcctCnt += safeInt(elemText(item, "accountnumber"));
                }
            }
        }
        out.put("badguabal", badGuaBal);
        out.put("attnguaacctcnt", attnGuaAcctCnt);

        // 模块5: ED03。balanceinterest(ED030J01)>0 时求和为未结清欠息余额。
        NodeList debitInterestNodes = nodeSet(innerDoc, "//debitInterestList/Crt2_C_DebitInterest");
        double unpaidIntBal = 0.0;
        if (debitInterestNodes != null) {
            for (int i = 0; i < debitInterestNodes.getLength(); i++) {
                Element item = (Element) debitInterestNodes.item(i);
                double balanceInterest = safeDouble(elemText(item, "balanceinterest"));
                if (balanceInterest > 0) {
                    unpaidIntBal += balanceInterest;
                }
            }
        }
        out.put("unpaidintbal", unpaidIntBal);

        log.info("qyzxbghz-after-end:sequenceId:{},odLoan={},badLoan={},attnLoan={},odGua={},badGua={},attnGua={},unpaidInt={},reportId={},statusCode={}",
            context.getSequenceId(), out.get("odloanacctcnt"), out.get("badloanbal"), out.get("attnloanacctcnt"),
            out.get("odguaacctcnt"), out.get("badguabal"), out.get("attnguaacctcnt"), out.get("unpaidintbal"),
            out.get("qyzxbgreportid"), out.get("qyzxbgstatuscode"));
    } catch (Exception e) {
        log.error("[qyzxbghz-after error]sequenceId:{}", context.getSequenceId(), e);
    }
    return out;
}

@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("qyzxbghz-sendAfterOnce:sequenceId:{}", context.getSequenceId());
}

import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
