/**
 * 企业征信报告前置ETL (HTTP-POST, comSingleCacheQuery, T00221001)
 * 职责: 从DS inputMappings配置好的bodyMap读取所有参数, 构建SOAP 1.1 Envelope
 * 注意: 所有参数值(含定值/动态值)均来自DS inputConfig, ETL不硬编码任何值
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerBeforeCaller.class);

@Override
public void afterInitHttpContext(ChannelContext context, HttpContext httpContext) {
    if (log.isDebugEnabled()) {
        log.debug("qyzxbgQz-afterInitHttpContext-start:sequenceId:{},httpContext{}", context.getSequenceId(), JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect));
    } else {
        log.info("qyzxbgQz-afterInitHttpContext-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        Map<String, Object> bodyMap = httpContext.getBodyMap();

        StringBuilder soap = new StringBuilder(1024);
        soap.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        soap.append("<soapenv:Envelope");
        soap.append(" xmlns:soapenv=\"http://schemas.xmlsoap.org/soap/envelope/\"");
        soap.append(" xmlns:ser=\"http://service.webservice.credit2query.zxjk.com/\">");
        soap.append("<soapenv:Header/>");
        soap.append("<soapenv:Body>");
        soap.append("<ser:rtdsRequest>");
        soap.append("<RtdsRequest>");
        // 常量 inputMapping: bodyMap key = serviceParam（如 "transCode"）
        appendXmlTag(soap, "transCode",       bodyMap);
        appendXmlTag(soap, "sysId",           bodyMap);
        appendXmlTag(soap, "userId",          bodyMap);
        appendXmlTag(soap, "password",        bodyMap);
        appendXmlTag(soap, "entCertType",     bodyMap);
        appendXmlTag(soap, "queryReason",     bodyMap);
        appendXmlTag(soap, "queryType",       bodyMap);
        appendXmlTag(soap, "reportType",      bodyMap);
        appendXmlTag(soap, "reportModelType", bodyMap);
        // 变量 inputMapping: bodyMap key = field.name（非 serviceParam）
        // EtlUtil.java: key = mapping.getField()，value = paramMap.get(mapping.getField())
        appendXmlTagFrom(soap, "entName",    "S_S_COMPANYNAME",     bodyMap);
        appendXmlTagFrom(soap, "entCertNum", "C_S_QYUNIFSOCLCRCOD", bodyMap);
        soap.append("</RtdsRequest>");
        soap.append("</ser:rtdsRequest>");
        soap.append("</soapenv:Body>");
        soap.append("</soapenv:Envelope>");

        log.info("qyzxbgQz-afterInitHttpContext:sequenceId:{},soapLength={}", context.getSequenceId(), soap.length());

        httpContext.setRequestBody(soap.toString());
        httpContext.getHeaders().put("SOAPAction", "\"\"");
        httpContext.setHeaders(httpContext.getHeaders());

    } catch (Exception e) {
        log.error("[qyzxbgQz-afterInitHttpContext error]sequenceId:{}", context.getSequenceId(), e);
    }
}

@Override
public void beforeSendHttp(ChannelContext context) {}

@Override
public boolean isCompleted(byte[] allMsg) { return true; }

private void appendXmlTag(StringBuilder sb, String tag, Map<String, Object> bodyMap) {
    Object val = bodyMap.get(tag);
    String text = (val != null) ? val.toString().trim() : "";
    if (!text.isEmpty()) {
        sb.append("<").append(tag).append(">").append(escapeXml(text)).append("</").append(tag).append(">");
    } else {
        sb.append("<").append(tag).append("/>");
    }
}

/**
 * 变量 inputMapping 专用: bodyMap key 为 field.name（非 serviceParam）
 * 对应 EtlUtil.java: key = mapping.getField()
 */
private void appendXmlTagFrom(StringBuilder sb, String xmlTag, String bodyMapKey, Map<String, Object> bodyMap) {
    Object val = bodyMap.get(bodyMapKey);
    String text = (val != null) ? val.toString().trim() : "";
    if (!text.isEmpty()) {
        sb.append("<").append(xmlTag).append(">").append(escapeXml(text)).append("</").append(xmlTag).append(">");
    } else {
        sb.append("<").append(xmlTag).append("/>");
    }
}

private String escapeXml(String s) {
    if (s == null) return "";
    return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
             .replace("\"", "&quot;").replace("'", "&apos;");
}

import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import com.alibaba.fastjson.JSON;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.apache.commons.lang3.ObjectUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;
import java.util.Map;

/**
 * 882法院公告核查后置ETL（分页，PAGE）。
 * 企查查按PublishDate倒序返回，earlyStop=true：遇超90天记录即flag=false终止翻页。
 * 过滤条件（同时满足）：
 *   1. PublishDate距今<90天
 *   2. CaseReason包含: 借款合同/民间借贷/金融借款合同/票据/借贷/拆借/融资租赁
 *   3. RoleList中RoleType="1"(被告)且RoleItemList中有Name匹配searchKey的条目
 * 跨页状态: 使用etlHandlerContext.getBussMap()累计count和detail。
 * 输出字段:
 *   ent3mCourtNoticeLoanDisputeDefendantCntQcc: 近3个月被告借款纠纷案件数
 *   ent3mCourtNoticeLoanDisputeDefendantDetailQcc: 案件详情JSONArray
 *   statusCode882fygghc: 接口HTTP状态码
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

/**
 * 后置处理逻辑（自定义解析、数据加工）
 *
 * @param context  全局上下文
 * @param response 数据源响应原始报文
 * @return 服务配置输出Map
 */
@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        JSONObject responseJson = JSON.parseObject(response);
        String status = responseJson.getString("Status");
        // 状态码写入输出，供规则判断接口是否正常返回
        int statusCode = (status == null) ? 0 : Integer.parseInt(status);
        outputMap.put("statusCode882fygghc", statusCode);

        // flag默认true（激进策略：默认继续翻页，在终止条件下置false）
        boolean flag = true;

        // 上下文对象延迟声明为null（防御性：status非200时无需获取）
        EtlHandlerContext etlHandlerContext = null;
        EtlRequestResult etlRequestResult = null;
        Map<String, String> allParam = null;       // allParam：含所有入参展开值，key=DS字段名（如C_S_PAGEINDEX），用于读取当前页码
        Map<String, String> requestInParam = null; // requestInParam：可写入下一页入参，平台在下次调用时读取

        if ("200".equals(status)) {

            //===== 上下文获取：独立try-catch，获取失败则停止翻页 =====
            // 修复：先获取requestInParam（MOCK模式与非MOCK模式均可用），再null-safe获取etlRequestResult
            // 原代码在MOCK模式下etlRequestResult==null，getAllParam()触发NPE→catch→flag=false→allParam=null→searchKey=""
            try {
                etlHandlerContext = context.getEtlHandlerContext();
                requestInParam = etlHandlerContext.getRequestInParam();  // 先获取，MOCK模式下也可用
                EtlRequestResult tempResult = etlHandlerContext.getEtlRequestResult();
                if (tempResult != null) {  // MOCK模式下etlRequestResult未初始化为null，正常现象
                    etlRequestResult = tempResult;
                    allParam = etlRequestResult.getAllParam();
                }
            } catch (Exception e) {
                flag = false; // 真正的上下文获取失败才终止翻页
                e.printStackTrace();
            }

            //===== 业务处理 =====
            JSONObject resultObj = responseJson.getJSONObject("Result");
            if (resultObj == null || resultObj.getIntValue("VerifyResult") == 0) {
                // VerifyResult=0：无数据，显式置flag=false
                flag = false;
                outputMap.put("ent3mCourtNoticeLoanDisputeDefendantCntQcc", 0);
                outputMap.put("ent3mCourtNoticeLoanDisputeDefendantDetailQcc", new JSONArray().toJSONString());
            } else {
                // 获取searchKey：优先从requestInParam读取（MOCK和非MOCK模式均可用）
                // allParam在MOCK模式下为null（InvokeStep被跳过，parseRequestParam未执行）
                String searchKey = (requestInParam != null) ? (String) requestInParam.get("C_S_QCCSEARCHKEY") : "";
                if (searchKey == null) { searchKey = ""; }

                LocalDate today = LocalDate.now();
                DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");

                // 累计变量在bussMap try-catch外声明（保证bussMap异常时仍有输出）
                int accCnt = 0;
                JSONArray accDetail = new JSONArray();

                //===== bussMap跨页状态操作：独立try-catch =====
                try {
                    // bussMap：平台原生跨页状态容器，同一请求多次after()间共享，平台管理生命周期
                    Map<String, Object> bussMap = etlHandlerContext.getBussMap();
                    // 恢复上一页写入的累计状态（首页时bussMap为空，使用上方声明的初始值）
                    if (bussMap.containsKey("accCnt")) { accCnt = ((Number) bussMap.get("accCnt")).intValue(); }
                    if (bussMap.containsKey("accDetail")) { accDetail = JSON.parseArray(bussMap.get("accDetail").toString()); }

                    JSONArray dataArray = resultObj.getJSONArray("Data");
                    if (dataArray != null) {
                        for (int i = 0; i < dataArray.size(); i++) {
                            JSONObject item = dataArray.getJSONObject(i);

                            // 读取PublishDate，取前10字符（yyyy-MM-dd），兼容"yyyy-MM-dd HH:mm:ss"格式
                            String publishDateStr = item.getString("PublishDate");
                            if (publishDateStr == null || publishDateStr.isEmpty()) {
                                continue; // 无日期记录跳过
                            }
                            if (publishDateStr.length() > 10) {
                                publishDateStr = publishDateStr.substring(0, 10);
                            }
                            LocalDate publishDate = LocalDate.parse(publishDateStr, fmt);
                            long daysAgo = ChronoUnit.DAYS.between(publishDate, today);

                            // earlyStop：企查查按倒序返回，遇超90天记录则后续均超，flag=false并终止循环
                            if (daysAgo >= 90) {
                                flag = false;
                                break;
                            }

                            // 过滤：CaseReason必须包含借款合同纠纷相关关键词
                            String caseReason = item.getString("CaseReason");
                            if (!containsCaseReason(caseReason)) {
                                continue; // 案由不匹配，跳过
                            }

                            // 过滤：目标公司必须为被告（RoleType="1"的RoleItemList中Name匹配searchKey）
                            if (!isDefendant(item, searchKey)) {
                                continue; // 非被告角色，跳过
                            }

                            // 符合全部过滤条件，累计计入被告借款纠纷案件
                            accCnt++;
                            JSONObject detailItem = new JSONObject();
                            String v1 = item.getString("CaseNo"); if (v1 != null) { detailItem.put("caseno", v1); }         // 案号
                            String v2 = item.getString("CaseReason"); if (v2 != null) { detailItem.put("casereason", v2); } // 案由
                            String v3 = item.getString("Category"); if (v3 != null) { detailItem.put("category", v3); }     // 公告类型
                            String v4 = item.getString("Court"); if (v4 != null) { detailItem.put("court", v4); }           // 公告人
                            String v5 = item.getString("PublishDate"); if (v5 != null) { detailItem.put("publishdate", v5); } // 刊登日期
                            JSONArray pl = item.getJSONArray("ProsecutorList"); if (pl != null) { detailItem.put("prosecutorlist", pl); }   // 原告列表
                            JSONArray dl = item.getJSONArray("DefendantList"); if (dl != null) { detailItem.put("defendantlist", dl); }       // 被告列表
                            accDetail.add(detailItem);
                        }
                    }

                    // 写回跨页状态（平台管理生命周期，无需手动清理）
                    bussMap.put("accCnt", accCnt);
                    bussMap.put("accDetail", accDetail.toJSONString());
                    etlHandlerContext.setBussMap(bussMap);
                    context.setEtlHandlerContext(etlHandlerContext); // 仅在setBussMap后调用一次

                } catch (Exception e) {
                    flag = false; // bussMap操作异常，停止翻页
                    e.printStackTrace();
                }

                // 输出在bussMap try-catch外（保证bussMap失败时仍有默认输出）
                outputMap.put("ent3mCourtNoticeLoanDisputeDefendantCntQcc", accCnt);
                outputMap.put("ent3mCourtNoticeLoanDisputeDefendantDetailQcc", accDetail.toJSONString());

                //===== 分页控制：在业务处理之后、独立try-catch =====
                try {
                    if (flag) {
                        JSONObject pagingObject = responseJson.getJSONObject("Paging");
                        if (pagingObject != null) {
                            Integer total = pagingObject.getIntValue("TotalRecords");
                            String currentFrom = ObjectUtils.isEmpty(allParam.get("C_S_PAGEINDEX")) ? "1"
                                               : (String) allParam.get("C_S_PAGEINDEX");
                            String size = ObjectUtils.isEmpty(allParam.get("C_S_PAGESIZE"))
                                          || "0".equals(allParam.get("C_S_PAGESIZE")) ? "20"
                                        : (String) allParam.get("C_S_PAGESIZE");
                            log.info("882fygghchz-after:sequenceId:{},from={},size={},total={}",
                                    context.getSequenceId(), currentFrom, size, total);
                            // ceil(total/size)：2参数divide + setScale（与参考实现一致）
                            int totalPage = new BigDecimal(total)
                                    .divide(new BigDecimal(size)).setScale(0, BigDecimal.ROUND_UP).intValue();
                            if (Integer.valueOf(currentFrom) < totalPage) {
                                requestInParam.put("C_S_PAGEINDEX",
                                        String.valueOf(Integer.parseInt(currentFrom) + 1));
                                etlHandlerContext.setRequestInParam(requestInParam);
                                // setRequestInParam后不再调用context.setEtlHandlerContext（已在setBussMap时调用）
                                flag = true;
                                log.info("882fygghchz-after:sequenceId:{},context={}",
                                        context.getSequenceId(), JSON.toJSONString(context));
                            } else {
                                flag = false; // 已是最后一页
                            }
                        } else {
                            flag = false; // Paging节点缺失
                        }
                    }
                } catch (Exception e) {
                    flag = false; // 分页计算异常，停止翻页
                    e.printStackTrace();
                }
            }
        } else {
            // 非200状态，终止翻页
            flag = false;
            outputMap.put("ent3mCourtNoticeLoanDisputeDefendantCntQcc", 0);
            outputMap.put("ent3mCourtNoticeLoanDisputeDefendantDetailQcc", new JSONArray().toJSONString());
        }

        context.setPageNextLoop(flag);

    } catch (Exception e) {
        log.error("[882fygghchz-after]sequenceId:{},context:{}", context.getSequenceId(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        context.setPageNextLoop(false);
    }
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("ICustomEtlHandlerAfterCaller-after-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

/**
 * 判断案由是否为借款合同纠纷相关类型
 */
private boolean containsCaseReason(String caseReason) {
    if (caseReason == null || caseReason.isEmpty()) { return false; }
    return caseReason.contains("借款合同") || caseReason.contains("民间借贷")
        || caseReason.contains("金融借款合同") || caseReason.contains("票据")
        || caseReason.contains("借贷") || caseReason.contains("拆借")
        || caseReason.contains("融资租赁");
}

/**
 * 判断案件记录中目标公司是否为被告（RoleType="1"且RoleItemList中Name匹配searchKey）
 */
private boolean isDefendant(JSONObject item, String searchKey) {
    if (searchKey == null || searchKey.isEmpty()) { return false; }
    // DefendantList为空则必定非被告
    JSONArray defendantList = item.getJSONArray("DefendantList");
    if (defendantList == null || defendantList.isEmpty()) { return false; }
    // 通过RoleList精确匹配RoleType="1"(被告)的当事人名称
    JSONArray roleList = item.getJSONArray("RoleList");
    if (roleList != null) {
        for (int j = 0; j < roleList.size(); j++) {
            JSONObject role = roleList.getJSONObject(j);
            if ("1".equals(role.getString("RoleType"))) { // RoleType=1为被告
                JSONArray roleItems = role.getJSONArray("RoleItemList");
                if (roleItems != null) {
                    for (int k = 0; k < roleItems.size(); k++) {
                        JSONObject roleItem = roleItems.getJSONObject(k);
                        if (searchKey.equals(roleItem.getString("Name"))) {
                            return true; // 目标公司在被告列表中
                        }
                    }
                }
            }
        }
    }
    return false;
}

