import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerBeforeCaller;
import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.serializer.SerializerFeature;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.security.MessageDigest;
import java.util.HashMap;
import java.util.Map;

/**
 * 企查查通用前置ETL：生成Token/Timespan签名并注入Header，删除SecretKey避免出现在URL中。
 * Token = MD5(key + Timespan + SecretKey).toUpperCase()，32位大写。
 * urlMap以field.name作key：C_S_QCCAPPKEY存appKey，C_S_QCCSECRETKEY存secretKey。
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerBeforeCaller.class);

/**
 * httpContext初始化完成之后（http参数已经封装完成）
 *
 * @param context     全局上下文对象
 * @param httpContext http上下文对象
 */
@Override
public void afterInitHttpContext(ChannelContext context, HttpContext httpContext) {
    if (log.isDebugEnabled()) {
        log.debug("ICustomEtlHandlerBeforeCaller-afterInitHttpContext-start:sequenceId:{},httpContext{}", context.getSequenceId(),
                JSON.toJSONString(httpContext, SerializerFeature.DisableCircularReferenceDetect));
    } else {
        log.info("ICustomEtlHandlerBeforeCaller-afterInitHttpContext-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        // urlMap以field.name作key读取企查查凭据（非serviceParam名）
        Map<String, Object> urlMap = httpContext.getUrlMap();
        String appKey = (String) urlMap.get("C_S_QCCAPPKEY");
        String secretKey = (String) urlMap.get("C_S_QCCSECRETKEY");
        // 生成Timespan（Unix秒级时间戳）
        String timespan = String.valueOf(System.currentTimeMillis() / 1000L);
        // 计算Token = MD5(key + Timespan + SecretKey).toUpperCase()，企查查签名规范要求32位大写
        String rawStr = (appKey != null ? appKey : "") + timespan + (secretKey != null ? secretKey : "");
        String token = md5UpperCase(rawStr);
        log.info("qcctyqzetl:sequenceId:{},timespan={}", context.getSequenceId(), timespan);
        // 设置HTTP Header：Token和Timespan由企查查签名规范要求
        Map<String, Object> headerMap = new HashMap<String, Object>();
        headerMap.put("Token", token);
        headerMap.put("Timespan", timespan);
        httpContext.setHeaders(headerMap);
        // 从urlMap删除SecretKey（field.name作key），使其不出现在最终请求URL中
        urlMap.remove("C_S_QCCSECRETKEY");
        httpContext.setUrlMap(urlMap);
    } catch (Exception e) {
        log.error("[ICustomEtlHandlerBeforeCaller-afterInitHttpContext invoke error]sequenceId:{},className:{},context:{}", context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
    }
}

/**
 * MD5计算辅助方法，返回32位大写字符串
 */
private String md5UpperCase(String input) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] bytes = md.digest(input.getBytes("UTF-8"));
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02X", b & 0xff));
        }
        return sb.toString();
    } catch (Exception e) {
        log.error("md5UpperCase error", e);
        return "";
    }
}

