import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.Map;
import java.util.HashMap;

/**
 * 预警通区域经济月度大全后置ETL（非分页，SEARCH_MYSQL协议）
 *
 * 数据来源：TQ_CIBD_REGIFIN_QUAR 区域金融季度指标表
 *   SQL查询当前季度+上一季度，返回16类原始指标（见INDICNAME列表）
 *
 * response格式（SEARCH_MYSQL）：{"content":"[{INDICNAME,QUAR,MVALUE,...},...]"}
 *   content 值为 JSON 数组字符串，需二次解析（v6修复点）
 *
 * STATDIMCODE含义：'1'=累计值（主要指标）/ '2'=当期值（土地出让环比用）
 *
 * 同组合多行去重：SQL ORDER BY PROJCODE ASC，ETL取首次出现值（最小PROJCODE=主报送口径）
 *
 * 综合财力：gi + zysr + govFund + stateCapInc（含转移性收入）
 * 全口径综合财力：gi + govFund + stateCapInc + subsidy（含上级补助，不含转移性收入）
 *
 * 输出（outputMap key = DS serviceParam = suffixName小写）：
 *   fiscalselfsufficiencyrate         → C_F_FISCALSELFSUFFICIENCYRATE          财政自给率（Row2）
 *   liabilityratio                    → C_F_LIABILITYRATIO                      负债率（Row3）
 *   broadliabilityratio               → C_F_BROADLIABILITYRATIO                 宽口径负债率（Row4）
 *   debtratio                         → C_F_DEBTRATIO                           债务率（Row5）
 *   broaddebtratio                    → C_F_BROADDEBTRATIO                      宽口径债务率（Row6）
 *   specialbondratio                  → C_F_SPECIALBONDRATIO                    专项债占比（Row7）
 *   debtlimitusagerate                → C_F_DEBTLIMITUSAGERATE                  债务限额使用率（Row8）
 *   lgfvdebtratio                     → C_F_LGFVDEBTRATIO                       城投债务占比（Row9）
 *   comprehensivedebtratio            → C_F_COMPREHENSIVEDEBTRATIO              综合债务率（Row10）
 *   taxrevenueratio                   → C_F_TAXREVENUERATIO                     税收占比（Row11）
 *   landsaledependency                → C_F_LANDSALEDEPENDENCY                  土地出让收入依赖度（Row12）
 *   landsalerevenuemom                → C_F_LANDSALEREVENUEMOM                  土地出让收入环比（Row13）
 *   fiscalselfsufficiencycurrentmonth → C_F_FISCALSELFSUFFICIENCYCURRENTMONTH   财政自给率本月=当季（Row14a）
 *   fiscalselfsufficiencylastmonth    → C_F_FISCALSELFSUFFICIENCYLASTMONTH      财政自给率上月=上季（Row14b）
 *   yjtqyjjyddqstatuscode             → C_N_YJTQYJJYDDQSTATUSCODE               状态码
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

private double safeDiv(double a, double b) {
    if (b == 0.0 || Double.isNaN(b) || Double.isInfinite(b)) { return 0.0; }
    return a / b;
}

private double getVal(Map<String, Double> m, String key) {
    Double v = (Double) m.get(key);
    if (v == null || Double.isNaN(v.doubleValue()) || Double.isInfinite(v.doubleValue())) { return 0.0; }
    return v.doubleValue();
}

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("qyjjyddqhz-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("qyjjyddqhz-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        // ---- 第一步：解析 SEARCH_MYSQL DS response ----
        // 格式A: "[{...}]"  直接 JSON 数组
        // 格式B: {"Data":[...]}  HTTP包装格式
        // 格式C: {"content":"[{...}]"}  SEARCH_MYSQL DS 实际格式（v6修复点）
        JSONArray rows = null;
        if (response != null && response.trim().startsWith("[")) {
            rows = JSON.parseArray(response);
        } else if (response != null && !response.trim().isEmpty()) {
            JSONObject wrapper = JSON.parseObject(response);
            if (wrapper != null) {
                rows = wrapper.getJSONArray("Data");
                if (rows == null) { rows = wrapper.getJSONArray("data"); }
                if (rows == null) { rows = wrapper.getJSONArray("rows"); }
                if (rows == null) {
                    // 格式C：content 键（SEARCH_MYSQL DS 实际格式，v6关键修复）
                    String contentStr = wrapper.getString("content");
                    if (contentStr != null && contentStr.trim().startsWith("[")) {
                        rows = JSON.parseArray(contentStr);
                        log.info("qyjjyddqhz-content格式,rows={} sequenceId:{}", rows != null ? rows.size() : -1, context.getSequenceId());
                    }
                }
            }
        }

        if (rows == null || rows.size() == 0) {
            log.info("qyjjyddqhz:无指标数据 sequenceId:{}", context.getSequenceId());
            outputMap.put("yjtqyjjyddqstatuscode", 1);
            return outputMap;
        }

        // ---- 第二步：构建指标字典 + 季度推断 ----
        // key = INDICNAME + "|" + QUAR + "|" + STATDIMCODE
        // SQL ORDER BY PROJCODE ASC：同组合多行取首条（最小PROJCODE=主报送口径）
        Map<String, Double> indicMap = new HashMap<String, Double>();
        String latestQuar = "";
        String prevQuar   = "";

        for (int i = 0; i < rows.size(); i++) {
            JSONObject row = rows.getJSONObject(i);
            if (row == null) { continue; }
            String indicName = row.getString("INDICNAME");
            String quar      = row.getString("QUAR");
            Double mvalueObj = row.getDouble("MVALUE");
            String statDim   = row.getString("STATDIMCODE");
            if (indicName == null || quar == null || mvalueObj == null) { continue; }

            if (latestQuar.length() == 0 || quar.compareTo(latestQuar) > 0) {
                if (latestQuar.length() > 0) { prevQuar = latestQuar; }
                latestQuar = quar;
            } else if (quar.compareTo(latestQuar) < 0) {
                if (prevQuar.length() == 0 || quar.compareTo(prevQuar) > 0) { prevQuar = quar; }
            }

            String mapKey = indicName + "|" + quar + "|" + (statDim != null ? statDim : "1");
            if (!indicMap.containsKey(mapKey)) {
                indicMap.put(mapKey, mvalueObj.doubleValue());
            }
        }

        String Q  = latestQuar;
        String PQ = prevQuar;

        // ---- 第三步：取当前季度原始指标（STATDIMCODE=1 累计值）----
        double gi          = getVal(indicMap, "一般公共预算收入|"            + Q + "|1");
        double ge          = getVal(indicMap, "一般公共预算支出|"            + Q + "|1");
        double debt        = getVal(indicMap, "地方政府债务余额|"            + Q + "|1");
        double debtSpec    = getVal(indicMap, "地方政府债务余额_专项债务|"    + Q + "|1");
        double gdp         = getVal(indicMap, "地区生产总值|"               + Q + "|1");
        double tax         = getVal(indicMap, "税收收入|"                   + Q + "|1");
        double govFund     = getVal(indicMap, "政府性基金收入|"              + Q + "|1");
        double stateCapInc = getVal(indicMap, "国有资本经营预算收入|"         + Q + "|1");
        double land1       = getVal(indicMap, "国有土地使用权出让收入|"        + Q + "|1");  // 累计值，用于依赖度
        double citou       = getVal(indicMap, "融资平台有息债务|"             + Q + "|1");  // 城投，暂缺时=0
        double debtLimit   = getVal(indicMap, "地方政府债务限额|"            + Q + "|1");  // 限额，暂缺时=0
        double zysr        = getVal(indicMap, "转移性收入|"                  + Q + "|1");  // 转移性，暂缺时=0
        double subsidy     = getVal(indicMap, "上级补助收入|"                + Q + "|1");  // 上级补助，暂缺时=0
        // 土地出让当期值（STATDIMCODE=2），用于环比（Row13注：指标为当期值）
        double land2Cur    = getVal(indicMap, "国有土地使用权出让收入|"        + Q  + "|2");
        double land2Prev   = getVal(indicMap, "国有土地使用权出让收入|"        + PQ + "|2");
        // 上季度（Row14b 财政自给率上月）
        double giPrev      = getVal(indicMap, "一般公共预算收入|"             + PQ + "|1");
        double gePrev      = getVal(indicMap, "一般公共预算支出|"             + PQ + "|1");

        // ---- 第四步：计算综合财力基数 ----
        double zhcl   = gi + zysr + govFund + stateCapInc;   // 含转移性收入
        double qkZhcl = gi + govFund + stateCapInc + subsidy; // 含上级补助，不含转移性

        // ---- 第五步：计算14个指标 + 输出 ----
        outputMap.put("fiscalselfsufficiencyrate",         safeDiv(gi, ge));                                     // Row2
        outputMap.put("liabilityratio",                    gdp   > 0 ? safeDiv(debt, gdp) : 0.0);       // Row3
        outputMap.put("broadliabilityratio",               gdp   > 0 ? safeDiv(debt + citou, gdp) : 0.0);  // Row4
        outputMap.put("debtratio",                         zhcl  > 0 ? safeDiv(debt, zhcl) : 0.0);      // Row5
        outputMap.put("broaddebtratio",                    zhcl  > 0 ? safeDiv(debt + citou, zhcl) : 0.0); // Row6
        outputMap.put("specialbondratio",                  debt  > 0 ? safeDiv(debtSpec, debt) : 0.0);           // Row7
        outputMap.put("debtlimitusagerate",                debtLimit > 0 ? safeDiv(debt, debtLimit) : 0.0);      // Row8
        outputMap.put("lgfvdebtratio",                     (debt + citou) > 0 ? safeDiv(citou, debt + citou) : 0.0); // Row9
        outputMap.put("comprehensivedebtratio",            qkZhcl > 0 ? safeDiv(debt + citou, qkZhcl) : 0.0); // Row10
        outputMap.put("taxrevenueratio",                   gi    > 0 ? safeDiv(tax, gi) : 0.0);                  // Row11
        outputMap.put("landsaledependency",                qkZhcl > 0 ? safeDiv(land1, qkZhcl) : 0.0);          // Row12
        outputMap.put("landsalerevenuemom",                land2Prev > 0 ? safeDiv(land2Cur - land2Prev, land2Prev) : 0.0); // Row13（当期值）
        outputMap.put("fiscalselfsufficiencycurrentmonth", safeDiv(gi, ge));                                     // Row14a 本季
        outputMap.put("fiscalselfsufficiencylastmonth",    gePrev > 0 ? safeDiv(giPrev, gePrev) : 0.0);          // Row14b 上季
        outputMap.put("yjtqyjjyddqstatuscode",             1);

    } catch (Exception e) {
        log.error("[qyjjyddqhz-exception]sequenceId:{},className:{},context:{}",
                context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        outputMap.put("yjtqyjjyddqstatuscode", -1);
    }
    if (log.isDebugEnabled()) {
        log.debug("qyjjyddqhz-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("qyjjyddqhz-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("qyjjyddqhz-sendAfterOnce:sequenceId:{}", context.getSequenceId());
    try {
    } catch (Exception e) {
        log.error("[qyjjyddqhz-sendAfterOnce error]sequenceId:{}", context.getSequenceId(), e);
    }
}

