import java.util.ArrayList;
import java.util.HashSet;
import java.util.Set;

/**
 * 预警通新闻舆情后置ETL（非分页，SEARCH_MYSQL协议）
 *
 * 数据来源：3张表JOIN查询（90天内，b.CR0001_008=企业统一社会信用代码）
 *   X_NEWS_TCRNW0003_ALL_V2  新闻-机构关联表（情感分类 CRNW0003_006）
 *   X_NEWS_TCRNWITCODE       机构码表（统一社会信用代码 CR0001_008）
 *   X_NEWS_TCRNW0001         新闻主表（标题 CRNW0001_003/来源 CRNW0001_007）
 *
 * response格式（SEARCH_MYSQL）：{"content":"[{NewsCode,...},...]"}
 *   其中 content 值为 JSON 数组字符串，需二次解析
 *
 * 处理逻辑：
 *   1. 按 NewsCode 去重（JOIN 导致同一新闻可能重复）
 *   2. 情感过滤：仅保留 sentiment(CRNW0003_006)='-1'（负面）
 *   3. 日期二次校验：NewsDate 在90天内（SQL层已过滤，此处双保险）
 *
 * 输出（outputMap key = DS serviceParam = suffixName小写）：
 *   negnewscnt                    → C_N_NEGNEWSCNT                    是否有负面舆情（0/1）
 *   enterprisenegativesentiment3m → C_S_ENTERPRISENEGATIVESENTIMENT3M  负面舆情详情JSON数组
 *   yjtxwyqstatuscode             → C_N_YJTXWYQSTATUSCODE              状态码（1成功/-1异常）
 */
private static Logger log = LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    if (log.isDebugEnabled()) {
        log.debug("yjtxwyqhz-start:sequenceId:{},response:{}", context.getSequenceId(), response);
    } else {
        log.info("yjtxwyqhz-start:sequenceId:{}", context.getSequenceId());
    }
    try {
        // ---- 第一步：解析 SEARCH_MYSQL DS response ----
        // 格式A: "[{...}]"  直接 JSON 数组（response 以 [ 开头）
        // 格式B: {"Data":[...]}  HTTP包装格式
        // 格式C: {"content":"[{...}]"}  SEARCH_MYSQL DS 实际格式（content 值为 JSON 数组字符串）
        JSONArray rows = null;
        if (response != null && response.trim().startsWith("[")) {
            rows = JSON.parseArray(response);
        } else if (response != null && !response.trim().isEmpty()) {
            JSONObject wrapper = JSON.parseObject(response);
            if (wrapper != null) {
                rows = wrapper.getJSONArray("Data");
                if (rows == null) { rows = wrapper.getJSONArray("data"); }
                if (rows == null) { rows = wrapper.getJSONArray("rows"); }
                if (rows == null) {
                    // 格式C：content 键（SEARCH_MYSQL DS 实际格式）
                    String contentStr = wrapper.getString("content");
                    if (contentStr != null && contentStr.trim().startsWith("[")) {
                        rows = JSON.parseArray(contentStr);
                        log.info("yjtxwyqhz-content格式,rows={} sequenceId:{}", rows != null ? rows.size() : -1, context.getSequenceId());
                    }
                }
            }
        }

        if (rows == null || rows.size() == 0) {
            log.info("yjtxwyqhz:无新闻数据 sequenceId:{}", context.getSequenceId());
            outputMap.put("negnewscnt", 0);
            outputMap.put("enterprisenegativesentiment3m", new JSONArray().toJSONString());
            outputMap.put("yjtxwyqstatuscode", 1);
            return outputMap;
        }

        // ---- 第二步：遍历、去重、过滤，构造负面新闻列表 ----
        long nowMs        = System.currentTimeMillis();
        long ninetyDaysMs = 90L * 24L * 60L * 60L * 1000L;
        List<JSONObject> negativeList = new ArrayList<JSONObject>();
        Set<String> seenCodes = new HashSet<String>();

        for (int i = 0; i < rows.size(); i++) {
            JSONObject row = rows.getJSONObject(i);
            if (row == null) { continue; }

            // 去重：同 NewsCode 只取一次
            String newsCode = row.getString("NewsCode");
            if (newsCode != null) {
                if (seenCodes.contains(newsCode)) { continue; }
                seenCodes.add(newsCode);
            }

            // 情感过滤：仅保留 CRNW0003_006='-1'（负面）
            String sentiment = row.getString("sentiment");
            if (!"-1".equals(sentiment)) { continue; }

            // 日期二次校验（SQL层已过滤，此处双保险）
            String newsDateStr = row.getString("NewsDate");
            if (newsDateStr != null && newsDateStr.trim().length() >= 10) {
                try {
                    String ds = newsDateStr.trim();
                    int yr = Integer.parseInt(ds.substring(0, 4));
                    int mo = Integer.parseInt(ds.substring(5, 7));
                    int dy = Integer.parseInt(ds.substring(8, 10));
                    java.util.Calendar cal = java.util.Calendar.getInstance();
                    cal.set(yr, mo - 1, dy, 0, 0, 0);
                    cal.set(java.util.Calendar.MILLISECOND, 0);
                    if ((nowMs - cal.getTimeInMillis()) > ninetyDaysMs) { continue; }
                } catch (Exception pe) { /* 解析失败则保留 */ }
            }

            // publishtime：优先 CRNW0001_018，fallback NewsDate
            String publishtime = row.getString("publishtime");
            if (publishtime == null || publishtime.startsWith("1900")) {
                publishtime = (newsDateStr != null) ? newsDateStr : "";
            }

            JSONObject item = new JSONObject();
            item.put("title",       row.getString("title")  != null ? (String) row.getString("title")  : "");
            item.put("publishtime", publishtime);
            item.put("sentiment",   sentiment);
            item.put("source",      row.getString("source") != null ? (String) row.getString("source") : "");
            item.put("content",     "");  // CLOB正文暂不包含
            negativeList.add(item);
        }

        // ---- 第三步：输出到 outputMap ----
        outputMap.put("negnewscnt",                    negativeList.size() > 0 ? 1 : 0);
        outputMap.put("enterprisenegativesentiment3m", JSON.toJSONString(negativeList));
        outputMap.put("yjtxwyqstatuscode",             1);

    } catch (Exception e) {
        log.error("[yjtxwyqhz-exception]sequenceId:{},className:{},context:{}",
                context.getSequenceId(), this.getClass().getName(),
                JSON.toJSONString(context, SerializerFeature.DisableCircularReferenceDetect), e);
        outputMap.put("negnewscnt",                    0);
        outputMap.put("enterprisenegativesentiment3m", new JSONArray().toJSONString());
        outputMap.put("yjtxwyqstatuscode",             -1);
    }
    if (log.isDebugEnabled()) {
        log.debug("yjtxwyqhz-end:sequenceId:{},outputMap:{}", context.getSequenceId(), outputMap);
    } else {
        log.info("yjtxwyqhz-end:sequenceId:{}", context.getSequenceId());
    }
    return outputMap;
}

@Override
public void sendAfterOnce(ChannelContext context, HttpContext httpContext) {
    log.info("yjtxwyqhz-sendAfterOnce:sequenceId:{}", context.getSequenceId());
    try {
    } catch (Exception e) {
        log.error("[yjtxwyqhz-sendAfterOnce error]sequenceId:{}", context.getSequenceId(), e);
    }
}

