import cn.tongdun.layout.engine.core.domain.context.HttpContext;
import cn.tongdun.layout.engine.core.domain.context.ChannelContext;
import cn.tongdun.layout.engine.core.domain.context.etl.EtlHandlerContext;
import cn.tongdun.layout.engine.core.domain.intf.etl.ICustomEtlHandlerAfterCaller;
import cn.tongdun.layout.engine.core.domain.model.etl.EtlRequestResult;
import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONObject;
import com.alibaba.fastjson.JSONArray;
import com.alibaba.fastjson.serializer.SerializerFeature;
import com.google.common.collect.Maps;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.Map;

private static Logger log=LoggerFactory.getLogger(ICustomEtlHandlerAfterCaller.class);

@Override
public Map<String, Object> after(ChannelContext context, String response) {
    Map<String, Object> outputMap = Maps.newHashMap();
    log.info("TxIpQueryPostEtl-after-start:sequenceId:{}", context.getSequenceId());
    try {
        JSONObject root = JSON.parseObject(response);
        JSONArray data = root.getJSONArray("data");
        JSONObject paging = root.getJSONObject("paging");

        EtlHandlerContext etlCtx = context.getEtlHandlerContext();
        Map<String, Object> allParam = etlCtx.getEtlRequestResult().getAllParam();
        Map<String, Object> requestIn = etlCtx.getRequestInParam();

        // Accumulate: take last non-null country/province from this page
        String country = null;
        String province = null;
        if (data != null) {
            for (int i = 0; i < data.size(); i++) {
                JSONObject item = data.getJSONObject(i);
                if (item.getString("country") != null) country = item.getString("country");
                if (item.getString("province") != null) province = item.getString("province");
            }
        }
        outputMap.put("S_S_IPCOUNTRY", country);
        outputMap.put("S_S_IPPROV", province);

        // Pagination control
        boolean hasNext = false;
        if (paging != null) {
            Integer total = paging.getInteger("total");
            Integer pageSize = paging.getInteger("pageSize");
            Integer pageIndex = paging.getInteger("pageIndex");
            if (total != null && pageSize != null && pageIndex != null) {
                int totalPages = (total + pageSize - 1) / pageSize;
                if (pageIndex < totalPages) {
                    hasNext = true;
                    requestIn.put("pageIndex", String.valueOf(pageIndex + 1));
                }
            }
        }
        context.setPageNextLoop(hasNext);
    } catch (Exception e) {
        log.error("[TxIpQueryPostEtl-after exception]sequenceId:{}", context.getSequenceId(), e);
        context.setPageNextLoop(false);
    }
    return outputMap;
}

@Override
